357	    const allData = [];
358	    const total = Math.min(conversations.length, 25);
359	    const imageDedup = new Set(); // 全局图片去重
360	
361	    for (let i = 0; i < total; i++) {
362	      const conv = conversations[i];
363	      if (conv.name === 'Assistant Eva官方') continue; // Skip system account
364	
365	      process.stdout.write(`\r💬 [${i + 1}/${total}] ${conv.name}...`);
366	
367	      const clicked = await clickConversation(talkFrame, i);
368	      if (!clicked) {
369	        console.log(`\n   ⚠️ 无法点击索引 ${i}`);
370	        continue;
371	      }
372	
373	      await waitForMessages(talkFrame);
374	
375	      // 滚动加载全部历史消息（虚拟滚动）
376	      const totalLoaded = await scrollChatToLoadAll(talkFrame);
377	
378	      const messages = await getRenderedMessages(talkFrame);
379	
380	      // 提取并保存该客户的图片（关联消息索引）
