385	
386	      // Re-get conv data to get current status
387	      const updatedList = await getConversationList(talkFrame);
388	      const current = updatedList[i] || conv;
389	
390	      allData.push({
391	        name: current.name,
392	        status: current.isUnread ? 'unread' : 'read',
393	        lastMessageSnippet: current.lastMessage,
394	        messageCount: messages.length,
395	        messages: messages.slice(-50), // Last 50 messages max
396	        images: savedImages.length > 0 ? savedImages : undefined,
397	      });
398	    }
399	
400	    console.log('\n');
401	
402	    // 4. 保存
403	    const timestamp = new Date().toISOString().replace(/[:]/g, '-').substring(0, 19);
404	    const outputPath = join(DATA_DIR, `数据快照_${timestamp}.json`);
405	    writeFileSync(outputPath, JSON.stringify(allData, null, 2), 'utf-8');
406	
407	    // 5. 生成摘要
408	    const totalMsg = allData.reduce((sum, c) => sum + c.messages.length, 0);
409	    const totalImg = allData.reduce((sum, c) => sum + (c.images?.length || 0), 0);
410	    const unreadCount = allData.filter(c => c.status === 'unread').length;
411	    console.log(`\n✅ 抓取完成`);
412	    console.log(`   会话: ${allData.length} | 总消息: ${totalMsg} | 图片: ${totalImg} | 未读: ${unreadCount}`);
413	    console.log(`   已保存: ${outputPath}`);
414	
415	    return allData;
416	  } finally {
417	    await browser.close();
418	  }
419	}
420	
421	async function frameEvaluateClickTab(frame, label) {
422	  return frame.evaluate((tabLabel) => {
423	    const tabs = document.querySelectorAll('.im-next-tabs-tab.list-tab-item');
424	    for (const tab of tabs) {
425	      if ((tab.textContent || '').trim() === tabLabel) {
426	        tab.click();
427	        return true;
428	      }
429	    }
430	    return false;
431	  }, label);
432	}
433	
434	scrapeAll().catch(err => {
435	  console.error('\n❌ 抓取失败:', err.message);
436	  process.exit(1);
437	});
