1	#!/usr/bin/env node
2	
3	/**
4	 * 小满CRM — TM + 邮件数据整合 v2
5	 *
6	 * 过滤系统邮件 → 按客户名合并 → 生成客户档案
7	 *
8	 * 用法: node integrate.mjs
9	 */
10	
11	import { readFileSync, writeFileSync, readdirSync } from 'fs';
12	import { join, dirname } from 'path';
13	import { fileURLToPath } from 'url';
14	
15	const __dirname = dirname(fileURLToPath(import.meta.url));
16	const DATA_DIR = join(__dirname, '..');
17	
18	// ============================================================
19	// 系统邮件黑名单
20	// ============================================================
21	const SYSTEM_SENDERS = [
22	  'feedback@service.alibaba.com',
23	  'feedback@email.alibaba.com',
24	  'alisourcepro@service.alibaba.com',
25	  'noreply@github.com',
26	  'notification@alibaba.com',
27	  'no-reply@alibaba.com',
28	];
29	
30	const SYSTEM_SUBJECT_PATTERNS = [
31	  'Alibaba Inquiry Notification',
32	  '银牌RFQ',
33	  'You received new messages',
34	  'GitHub Copilot',
35	  'Trade Center',
36	];
37	
38	function isSystemEmail(email) {
39	  const sender = (email.senderEmail || '').toLowerCase();
40	  if (SYSTEM_SENDERS.some(s => sender.includes(s))) return true;
41	  const subject = (email.subject || '');
42	  if (SYSTEM_SUBJECT_PATTERNS.some(p => subject.includes(p))) return true;
43	  return false;
44	}
45	
46	// ============================================================
47	// 加载数据
48	// ============================================================
49	function loadLatest(pattern) {
50	  const files = readdirSync(DATA_DIR)
51	    .filter(f => f.startsWith(pattern) && f.endsWith('.json'))
52	    .sort().reverse();
53	  if (!files.length) return [];
54	  return JSON.parse(readFileSync(join(DATA_DIR, files[0]), 'utf-8'));
55	}
56	
57	// ============================================================
58	// 匹配客户名
59	// ============================================================
60	function matchCustomer(text, names) {
61	  if (!text) return null;
62	  const lower = text.toLowerCase();
63	  for (const name of names) {
64	    if (!name || name === 'User name') continue;
65	    if (lower.includes(name.toLowerCase())) return name;
66	    const parts = name.toLowerCase().split(/\s+/).filter(Boolean);
67	    for (const part of parts) {
68	      if (part.length > 2 && lower.includes(part)) return name;
69	    }
70	  }
71	  return null;
72	}
73	
74	// ============================================================
75	// 主流程
76	// ============================================================
77	function main() {
78	  console.log('╔══════════════════════════════════════╗');
79	  console.log('║   小满CRM 数据整合 v2                ║');
80	  console.log('║   TM + 邮件(已过滤系统邮件)           ║');
81	  console.log('╚══════════════════════════════════════╝\n');
82	
83	  const tmData = loadLatest('数据_');
84	  const rawMail = loadLatest('邮件数据_');
85	  const sentData = loadLatest('发件数据_');
86	
87	  // 过滤系统邮件
88	  const systemEmails = rawMail.filter(isSystemEmail);
89	  const realEmails = rawMail.filter(e => !isSystemEmail(e));
90	
91	  // 发件全部是真实业务邮件，保留
92	  const realSent = [...sentData];
93	
94	  console.log(`📂 加载数据:`);
95	  console.log(`   TM 聊天: ${tmData.length} 个会话`);
96	  console.log(`   收件原始: ${rawMail.length} 封`);
97	  console.log(`   🗑️ 过滤系统邮件: ${systemEmails.length} 封`);
98	  console.log(`   ✅ 真实收件: ${realEmails.length} 封`);
99	  console.log(`   ✅ 真实发件: ${realSent.length} 封\n`);
100	
101	  const customerNames = [...new Set(tmData.map(c => c.name).filter(Boolean))];
102	  console.log(`👥 TM 客户: ${customerNames.length} 个`);
103	
104	  // 为每个客户建立档案
105	  const archives = customerNames.map(name => {
106	    const tm = tmData.find(c => c.name === name);
107	    const tmMessages = tm?.messages || [];
108	    const tmImages = tm?.images || [];
109	    const classification = tm?.classification || null;
110	
111	    // 匹配真实收件
112	    const inboxMails = realEmails.filter(m => m.customerName === name);
113	    // 匹配发件
114	    const sentMails = realSent.filter(m => {
115	      if (matchCustomer(m.senderName || m.senderEmail, [name])) return true;
116	      if (matchCustomer(m.subject || '', [name])) return true;
117	      return false;
118	    });
119	
120	    // 额外：从发件箱收件人找新客户（不在 TM 中的）
121	    const totalEmails = inboxMails.length + sentMails.length;
122	
123	    return {
124	      name,
125	      classification,
126	      tm: {
127	        messageCount: tmMessages.length,
128	        messages: tmMessages,
129	        images: tmImages,
130	      },
131	      emails: {
132	        total: totalEmails,
133	        inbox: inboxMails.map(m => ({
134	          subject: m.subject, time: m.time,
135	          body: m.bodyText?.substring(0, 3000) || '',
136	          images: m.images || [],
137	        })),
138	        sent: sentMails.map(m => ({
139	          to: m.senderName || m.senderEmail,
