const fs = require('fs');
const path = require('path');
const dir = 'd:/ClaudeWorkspace/08_客户跟进';
const file = fs.readdirSync(dir).filter(f => f.startsWith('数据_') && f.endsWith('.json')).sort().reverse()[0];
const data = JSON.parse(fs.readFileSync(path.join(dir, file), 'utf-8'));

// Dump key convos — the ones that have real interaction (not just card spam)
const interesting = data.filter(c => {
  const msgs = c.messages || [];
  const textMsgs = msgs.filter(m => m.content && m.content.length > 10 && !m.isCard);
  return textMsgs.length >= 3;
});

for (const c of interesting) {
  console.log('========================================');
  console.log('CUSTOMER:', c.name);
  console.log('CLASS:', c.classification?.categoryId, c.classification?.tier);
  console.log('---');
  const msgs = (c.messages || []).filter(m => m.content && m.content.length > 5);
  for (const m of msgs.slice(-10)) {
    const side = m.side === 'received' ? '📩客户' : m.side === 'sent' ? '📤我方' : '⚙️系统';
    const content = m.content.substring(0, 300);
    console.log(side + ': ' + content);
  }
  console.log('');
}
