#!/usr/bin/env node

/**
 * 小满CRM — 客户执行方案生成器
 * 输出精美排版的 Word 文档到桌面
 */

import { readFileSync, writeFileSync, readdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, WidthType, BorderStyle, ShadingType, TableLayoutType,
} from 'docx';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..');
const DESKTOP = 'C:/Users/Administrator/Desktop';

// ============================================================
// 调色板 — 阅读舒适为首要目标
// ============================================================
const C = {
  ink: '1A1A1A',        // 正文
  soft: '555555',       // 辅助文字
  light: '999999',      // 轻灰
  line: 'D9D9D9',       // 分隔线

  accent: '1A56DB',     // 主强调蓝
  accentBg: 'EEF2FF',   // 蓝底

  red: 'C92A2A',        // P0 紧急
  redBg: 'FFF5F5',      // P0 底色
  orange: 'D9480F',     // 高优
  orangeBg: 'FFF4EC',   // 高优底色
  yellow: 'B8860B',     // 关注
  yellowBg: 'FFFBE6',   // 关注底色

  green: '2B8A3E',      // 已处理
  greenBg: 'EBFBEE',
  purple: '7950F2',
  teal: '0C8599',

  white: 'FFFFFF',
  bg: 'FAFBFD',
};

// ============================================================
// 排版辅助
// ============================================================

function T(text, opts = {}) {
  return new TextRun({
    text,
    size: opts.size || 21,
    color: opts.color || C.ink,
    bold: opts.bold,
    italics: opts.italics,
    font: opts.font || 'Microsoft YaHei',
  });
}

function P(runs, opts = {}) {
  return new Paragraph({
    children: Array.isArray(runs) ? runs : [runs],
    spacing: { before: opts.before || 0, after: opts.after || 60, line: opts.line || 340 },
    indent: opts.indent,
    alignment: opts.alignment || AlignmentType.LEFT,
    border: opts.border,
    shading: opts.shading,
  });
}

function Spacer(h = 6) {
  return new Paragraph({ spacing: { before: h, after: h } });
}

function Divider() {
  return new Paragraph({
    children: [],
    spacing: { before: 120, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 1, color: C.line } },
  });
}

function Section(title, color) {
  return new Paragraph({
    children: [T(title, { size: 30, bold: true, color: color || C.accent })],
    spacing: { before: 360, after: 160 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 3, color: color || C.accent } },
  });
}

function Card(title, contents, { color = C.accent, bgColor = C.accentBg, icon = '' } = {}) {
  const paragraphs = [];

  // 卡片标题
  paragraphs.push(new Paragraph({
    children: [T((icon ? icon + ' ' : '') + title, { size: 24, bold: true, color })],
    spacing: { before: 200, after: 80 },
    shading: { fill: bgColor, type: ShadingType.CLEAR },
    indent: { left: 200 },
    border: { left: { style: BorderStyle.SINGLE, size: 8, color } },
  }));

  // 卡片内容
  for (const item of contents) {
    if (item.type === 'info') {
      paragraphs.push(new Paragraph({
        children: [
          T(item.label + '：', { size: 19, color: C.soft, bold: true }),
          T(item.value, { size: 19, color: C.ink }),
        ],
        spacing: { after: 30 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'msg') {
      const sideLabel = item.side === 'received' ? '📩 客户' : '📤 我方';
      const sideColor = item.side === 'received' ? C.purple : C.teal;
      paragraphs.push(new Paragraph({
        children: [
          T(sideLabel + '：', { size: 18, bold: true, color: sideColor }),
          T(item.text, { size: 18, color: C.soft }),
        ],
        spacing: { after: 20 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'action') {
      paragraphs.push(new Paragraph({
        children: [T('▸ ' + item.text, { size: 19, color: C.ink })],
        spacing: { before: 40, after: 20 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'reply') {
      paragraphs.push(new Paragraph({
        children: [T(item.text, { size: 18, color: C.ink, italics: true })],
        spacing: { before: 30, after: 40 },
        indent: { left: 560 },
        shading: { fill: 'F8F9FA', type: ShadingType.CLEAR },
        border: { left: { style: BorderStyle.SINGLE, size: 4, color: C.line } },
      }));
    } else if (item.type === 'highlight') {
      paragraphs.push(new Paragraph({
        children: [T('⚠ ' + item.text, { size: 18, color: C.red, bold: true })],
        spacing: { before: 40, after: 40 },
        indent: { left: 500 },
      }));
    }
  }

  return paragraphs;
}

// ============================================================
// 客户分析数据（硬编码 — 基于最新数据快照的分析结果）
// ============================================================

const actionPlan = {
  generatedAt: new Date(),
  summary: {
