    { label: 'P2/P3 常规', value: '4', sub: '本周处理', color: C.yellow, bg: C.yellowBg },
  ];

  children.push(
    new Table({
      rows: [
        new TableRow({
          children: statItems.map(s =>
            new TableCell({
