  // ==================== 页脚 ====================
  children.push(Divider());
  children.push(
    new Paragraph({
      children: [T('小星星服饰 · 小满CRM智能助手自动生成 · ' + `${now.getFullYear()}/${now.getMonth() + 1}/${now.getDate()}`, { size: 16, color: C.light })],
