    { done: false, text: 'Krisgel Igros — 发30pcs打包报价+菲律宾运费', pri: 'P1 48h' },
    { done: false, text: 'fernande Pochette — 发24pcs报价+美国估算运费', pri: 'P1 48h' },
    { done: false, text: 'Susuanna ParkerAdentwi — 发PI确认订单', pri: 'P1 48h' },
    { done: false, text: 'rehema kiseyu — 轻量跟进（发新面料消息）', pri: 'P1 本周' },
    { done: false, text: '5个低活跃客户 — 统一发工厂优势+畅销目录', pri: 'P2 本周' },
  ];

  for (const item of checklist) {
    const priColor = item.pri.startsWith('P0') ? C.red : item.pri.startsWith('P1') ? C.orange : C.yellow;
    children.push(
      new Paragraph({
        children: [
          T('☐ ', { size: 22, color: C.light }),
          T(item.text, { size: 19, color: C.ink }),
          T('  [' + item.pri + ']', { size: 16, bold: true, color: priColor }),
        ],
        spacing: { before: 20, after: 30 },
        indent: { left: 200 },
      }),
    );
  }

  // ==================== 七、关键提醒 ====================
  children.push(Divider());
  children.push(Section('七、关键提醒', C.red));

  const reminders = [
    '所有阿拉伯语客户的回复需要尽快处理 — 伊拉克和中东市场是核心目标市场，当前有4个阿拉伯语客户待回复',
    'azaan ss 的"How much"被问了三次还没给价格 — 这是最紧急的，今天必须给',
    '分类器把rehema kiseyu和azaan ss误判为"售后处理"，实际是询盘。需要修正分类规则：关键词"quality"不应单独触发after_sales',
    '我方回复模式存在问题：太多"I\'ll check with manager"/"I\'ll get back to you"，客户等太久。建议为常见产品制定标准报价区间，减少"问经理"的频率',
    '模板化A/B/C问卷对部分客户有效，但对已经发了具体产品卡片的客户，应该直接报价+提问，而不是先发问卷',
  ];

  for (const r of reminders) {
    children.push(
      new Paragraph({
        children: [T('• ' + r, { size: 18, color: C.soft })],
        spacing: { before: 20, after: 30 },
        indent: { left: 200 },
      }),
    );
  }

  // ==================== 附录 ====================
  children.push(Divider());
  children.push(Section('附录：回复优先级排序逻辑', C.light));

  children.push(
    new Paragraph({
      children: [T('排序依据：客户明确度 > 时效性 > 订单规模 > 市场价值', { size: 18, color: C.soft })],
      spacing: { after: 60 },
    }),
    new Paragraph({
      children: [T('• S级（今日必回）：客户已明确需求且多次追问，不回复即丢失', { size: 18, color: C.ink })],
      spacing: { after: 30 }, indent: { left: 200 },
    }),
    new Paragraph({
      children: [T('• A级（今日回）：客户发了询盘但有互动，需要报价或确认信息', { size: 18, color: C.ink })],
      spacing: { after: 30 }, indent: { left: 200 },
    }),
    new Paragraph({
      children: [T('• B级（48h内回）：有互动但进展早期，需要引导和培育', { size: 18, color: C.ink })],
      spacing: { after: 30 }, indent: { left: 200 },
    }),
    new Paragraph({
      children: [T('• C级（本周回）：低活跃客户，统一发送激活内容', { size: 18, color: C.ink })],
      spacing: { after: 60 }, indent: { left: 200 },
    }),
  );

  // ==================== 页脚 ====================
  children.push(Divider());
  children.push(
    new Paragraph({
      children: [T('小星星服饰 · 小满CRM智能助手自动生成 · ' + `${now.getFullYear()}/${now.getMonth() + 1}/${now.getDate()}`, { size: 16, color: C.light })],
      alignment: AlignmentType.CENTER,
      spacing: { before: 200 },
    }),
    new Paragraph({
      children: [T('所有建议回复话术基于外部专业调研SOP制定，请根据实际对话语境调整后发送', { size: 15, color: C.light })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 200 },
    }),
  );

  // ==================== 构建文档 ====================
  const doc = new Document({
    creator: '小满CRM助手',
    title: '小满CRM客户执行方案',
    description: '待处理客户回复建议和后续动作',
    styles: {
      default: {
        document: {
          run: { size: 21, font: 'Microsoft YaHei' },
        },
      },
    },
    sections: [{
      properties: {
        page: {
          margin: { top: 1200, bottom: 1200, left: 1400, right: 1400 },
        },
      },
      children,
    }],
  });

  // ==================== 保存到桌面 ====================
  const ts = `${now.getFullYear()}${String(now.getMonth() + 1).padStart(2, '0')}${String(now.getDate()).padStart(2, '0')}`;
  const outPath = join(DESKTOP, `小满CRM客户执行方案_${ts}.docx`);
  const buffer = await Packer.toBuffer(doc);
  writeFileSync(outPath, buffer);
  console.log(`\n✅ 文档已保存到桌面: ${outPath}`);
  return outPath;
}

build().catch(err => { console.error('\n❌ 错误:', err.message); process.exit(1); });

