/**
 * 小满CRM — 聊天记录抓取器 v2
 *
 * 用法: node scraper.mjs
 * 前置条件: Chrome 端口9222已开启，小满已登录并在TM消息页
 */

import { chromium } from 'playwright';
import { writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import { saveCustomerImages } from './image-utils.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..');
const CDP_URL = 'http://127.0.0.1:9222';

async function connect() {
  const browser = await chromium.connectOverCDP(CDP_URL);
  const ctx = browser.contexts()[0];
  const page = ctx.pages().find(p => p.url().includes('xiaoman'));
  if (!page) throw new Error('未找到小满页面');
  const talkFrame = page.frames()[1];
  if (!talkFrame) throw new Error('未找到聊天 iframe');
  return { browser, ctx, page, talkFrame };
}

/**
 * 提取会话列表
 */
async function getConversationList(frame) {
  return frame.evaluate(() => {
    return Array.from(document.querySelectorAll('.contact-item-container')).map(el => {
      const text = el.textContent || '';
      // Extract name from .contact-right (avoids avatar initial prefix issue)
      const nameEl = el.querySelector('.contact-right');
      const nameText = nameEl ? (nameEl.textContent || '').trim() : '';
      const nameMatch = nameText.match(/^(.+?)(?:\d{2,4}[-:\/])/);
      const name = nameMatch ? nameMatch[1].trim() : nameText.substring(0, 30).trim() || 'unknown';

      const isSelected = el.classList.contains('selected');
      const isUnread = text.includes('[未读]');
      const lastMsg = nameText.replace(/^.+?\d{2,4}[-:\/]\d{1,2}[-:\/]?\d{0,2}\s*/, '').replace(/\[(未读|已读)\]\s*/, '').trim();

      return { name, isUnread, isSelected, lastMessage: lastMsg.substring(0, 200) };
    });
  });
}

/**
 * 滚动会话列表到底部以确保所有项都在DOM中
 */
async function scrollConversationList(frame) {
  await frame.evaluate(() => {
    const container = document.querySelector('.seller-conversation-list') ||
      document.querySelector('.conversation-list-content') ||
      document.querySelector('.im-conversation-list-container');
    if (container) {
      container.scrollTop = container.scrollHeight;
    }
  });
  await new Promise(r => setTimeout(r, 500));
}

/**
 * 获取当前已渲染的消息（不含虚拟滚动未加载的旧消息）
 */
async function getRenderedMessages(frame) {
  return frame.evaluate(() => {
    const messages = [];
    const wrappers = document.querySelectorAll('.message-item-wrapper.messenger');

    wrappers.forEach((wrapper, index) => {
      const isLeft = wrapper.classList.contains('item-left');
      const isRight = wrapper.classList.contains('item-right');
      const isSystem = wrapper.hasAttribute('data-exp') && wrapper.getAttribute('data-exp') === 'sysmsg';

      const textEl = wrapper.querySelector('.session-rich-content.text');
      const cardEl = wrapper.querySelector('.session-rich-content.card');
      const securityEl = wrapper.querySelector('.session-security');
      const avatarEl = wrapper.querySelector('.session-avatar.head-portrait.messenger');
      const autoReply = wrapper.querySelector('.session-rich-content')?.textContent || '';

      // Skip security notices
      if (securityEl) return;

      // Determine message type
      let messageType = 'text';
      if (isSystem) messageType = 'system';
      else if (cardEl) messageType = 'card';

      const contentEl = textEl || cardEl;
      let content = contentEl ? contentEl.textContent.trim() : '';

      // Clean up content - remove translation artifacts
      content = content
        .replace(/翻译中…反馈$/, '')
        .replace(/由阿里翻译提供反馈$/, '')
        .replace(/阿里国际Marco大模型翻译反馈$/, '')
        .replace(/由阿里翻译提供$/, '')
        .trim();

      // Extract timestamp from p.item-base-info span:last-child
      const timeEl = wrapper.querySelector('p.item-base-info span:last-child');
      const timestamp = timeEl ? (timeEl.textContent || '').trim() : null;

      // Extract sender name
      const nameEl = wrapper.querySelector('p.item-base-info span.name');
      const sender = nameEl ? (nameEl.textContent || '').trim() : (avatarEl ? (avatarEl.textContent || '').trim() : '');

      // Extract emojis from img.emotion elements
      const emotionEls = wrapper.querySelectorAll('img.emotion');
      const emojis = Array.from(emotionEls).map(img => img.alt || img.src || '').filter(Boolean);

      // Detect content images (non-emotion, non-smiley)
      const contentImgs = wrapper.querySelectorAll('img');
      const hasImages = Array.from(contentImgs).some(img => {
        if (img.classList.contains('emotion')) return false;
        const s = img.src || '';
        if (!s.startsWith('http')) return false;
        if (s.includes('atmgateway-client.alibaba.com/smily')) return false;
        if (s.includes('clouddisk.alibaba.com')) return false;
        if (/tps-(48|60|72|80)-\d+\.(png|webp)/.test(s)) return false;
        return true;
      });

      // Detect file/cloud disk links (both <a> and <img> sources)
      const fileLinks = [];
      wrapper.querySelectorAll('a').forEach(a => {
        const href = a.href || '';
        if (href.includes('clouddisk') || href.includes('download') || href.includes('aliyundoc')) {
          fileLinks.push({ url: href, name: (a.textContent || '').trim() || (a.title || '') });
        }
      });
      // Also check img src for cloud disk files
      wrapper.querySelectorAll('img').forEach(img => {
        const s = img.src || '';
        if (s.includes('clouddisk.alibaba.com') && !fileLinks.some(f => f.url === s)) {
          fileLinks.push({ url: s, name: (img.alt || img.title || '') });
        }
      });

      // Auto-detect message type refinement
      if (!isSystem && !cardEl) {
        if (fileLinks.length > 0 && !content) {
          messageType = 'file';
        } else if (hasImages && !content) {
          messageType = 'image';
        }
      }

      // Extract card structured data if available
      let cardData = null;
      if (cardEl) {
        const expinfo = cardEl.getAttribute('data-expinfo');
        if (expinfo) {
          try { cardData = JSON.parse(expinfo); } catch (e) { /* ignore parse errors */ }
        }
        const cardImg = cardEl.querySelector('img');
        if (cardImg && cardImg.src && cardImg.src.startsWith('http')) {
          if (!cardData) cardData = {};
          cardData.imageUrl = cardImg.src;
        }
      }

      messages.push({
        index,
        side: isLeft ? 'received' : isRight ? 'sent' : 'system',
        content,
        messageType,
        timestamp,
        sender: sender || undefined,
        isCard: !!cardEl,
        cardData,
        emojis: emojis.length > 0 ? emojis : undefined,
        hasImages,
        fileLinks: fileLinks.length > 0 ? fileLinks : undefined,
        isAutoReply: autoReply.includes('自动接待发送') || autoReply.includes('去优化'),
        isSystem,
      });
    });

    return messages;
  });
}

/**
 * 滚动聊天区域加载所有历史消息（虚拟滚动）
 * Returns the scroll container selector used
 */
async function scrollChatToLoadAll(frame, { maxScrolls = 60, stableThreshold = 3 } = {}) {
  const containerInfo = await frame.evaluate(() => {
    // Try common scroll container selectors
    const selectors = [
      '.message-list-container',
      '.chat-list',
      '.im-chat-list',
      '.message-list',
      '[class*="message-list"]',
      '[class*="chat-list"]',
      '[class*="chat-content"]',
      '.session-message-list-wrapper',
    ];
    for (const sel of selectors) {
      const el = document.querySelector(sel);
      if (el && el.scrollHeight > el.clientHeight) {
        return { selector: sel, scrollHeight: el.scrollHeight, clientHeight: el.clientHeight };
      }
    }
    // Fallback: find any scrollable element containing messages
    const wrappers = document.querySelectorAll('.message-item-wrapper.messenger');
    if (wrappers.length > 0) {
      let el = wrappers[0].parentElement;
      while (el) {
        if (el.scrollHeight > el.clientHeight) {
          return { selector: null, found: true, scrollHeight: el.scrollHeight, clientHeight: el.clientHeight };
        }
        el = el.parentElement;
      }
    }
    return null;
  });

  if (!containerInfo) {
    console.log('   ⚠️ 未找到可滚动容器，使用当前渲染消息');
    return 0;
  }

  console.log(`   📜 滚动加载历史消息... (容器: ${containerInfo.selector || '自动检测'})`);

  let prevCount = 0;
  let stableCount = 0;
  let totalScrolled = 0;

  for (let i = 0; i < maxScrolls; i++) {
    const { count, scrolled } = await frame.evaluate(({ selector, containerInfo: ci }) => {
      // Find scroll container
      let container = null;
      if (selector) {
        container = document.querySelector(selector);
      } else {
        const wrappers = document.querySelectorAll('.message-item-wrapper.messenger');
        if (wrappers.length > 0) {
          let el = wrappers[0].parentElement;
          while (el) {
            if (el.scrollHeight > el.clientHeight) { container = el; break; }
            el = el.parentElement;
          }
        }
      }
      if (!container) return { count: 0, scrolled: false };

      const oldScrollTop = container.scrollTop;
      // Scroll to top to trigger loading of older messages
      container.scrollTop = 0;
      const scrolled = oldScrollTop > 0;
      return {
        count: document.querySelectorAll('.message-item-wrapper.messenger').length,
        scrolled,
      };
    }, { selector: containerInfo.selector, containerInfo });

    totalScrolled++;

    if (scrolled) {
      // Wait for virtual scroll to render new items
      await new Promise(r => setTimeout(r, 800));
    }

    const newCount = await frame.evaluate(() =>
      document.querySelectorAll('.message-item-wrapper.messenger').length
    );

    if (newCount === prevCount) {
      stableCount++;
      if (stableCount >= stableThreshold) break;
    } else {
      stableCount = 0;
      console.log(`      ${prevCount} → ${newCount} 条消息`);
    }
    prevCount = newCount;

    if (!scrolled) break;
  }

  console.log(`   ✅ 共加载 ${prevCount} 条消息 (滚动 ${totalScrolled} 次)`);
  return prevCount;
}

/**
 * 点击指定索引的联系人
 */
async function clickConversation(frame, index) {
  const result = await frame.evaluate((idx) => {
    const containers = document.querySelectorAll('.contact-item-container');
    const target = containers[idx];
    if (!target) return null;
    target.scrollIntoView({ block: 'center' });
    target.click();
    return (target.textContent || '').trim().substring(0, 150);
  }, index);
  await new Promise(r => setTimeout(r, 2000));
  return result;
}

/**
 * 等待并确认消息区域已更新（非空白）
 */
async function waitForMessages(frame) {
  for (let i = 0; i < 10; i++) {
    const hasContent = await frame.evaluate(() => {
      const msgs = document.querySelectorAll('.session-rich-content.text, .session-rich-content.card');
      return msgs.length > 0;
    });
    if (hasContent) return true;
    await new Promise(r => setTimeout(r, 500));
  }
  return false;
}

async function scrapeAll() {
  console.log('=== 小满CRM聊天记录抓取 v2 ===\n');
  const { browser, ctx, talkFrame } = await connect();
  console.log('✅ 已连接到小满');

  try {
    // 1. 获取完整会话列表
    console.log('\n📋 获取会话列表...');
    // Scroll to ensure all items rendered
    await scrollConversationList(talkFrame);
    await scrollConversationList(talkFrame);
    const conversations = await getConversationList(talkFrame);
    console.log(`   共 ${conversations.length} 个会话`);

    conversations.forEach((c, i) => {
      const status = c.isSelected ? '🟢' : c.isUnread ? '📩' : '  ';
      console.log(`  ${status} [${i}] ${c.name}`);
    });

    // 2. 切换各筛选Tab，统计
    console.log('\n📊 筛选统计...');
    const filterLabels = ['全部', '未读', '待回复', '待跟进'];
    const filterCounts = {};

    for (const label of filterLabels) {
      await frameEvaluateClickTab(talkFrame, label);
      const list = await getConversationList(talkFrame);
      filterCounts[label] = list.length;
      console.log(`   ${label}: ${list.length} 个会话`);
    }

    // 回到"全部"
    await frameEvaluateClickTab(talkFrame, '全部');
    await new Promise(r => setTimeout(r, 1000));

    // 3. 遍历所有会话获取详情（限前25个，避免太慢）
    const allData = [];
    const total = Math.min(conversations.length, 25);
    const imageDedup = new Set(); // 全局图片去重

    for (let i = 0; i < total; i++) {
      const conv = conversations[i];
      if (conv.name === 'Assistant Eva官方') continue; // Skip system account

      process.stdout.write(`\r💬 [${i + 1}/${total}] ${conv.name}...`);

      const clicked = await clickConversation(talkFrame, i);
      if (!clicked) {
        console.log(`\n   ⚠️ 无法点击索引 ${i}`);
        continue;
      }

      await waitForMessages(talkFrame);

      // 滚动加载全部历史消息（虚拟滚动）
      const totalLoaded = await scrollChatToLoadAll(talkFrame);

      const messages = await getRenderedMessages(talkFrame);

      // 提取并保存该客户的图片（关联消息索引）
      const savedImages = await saveCustomerImages(ctx, talkFrame, conv.name, imageDedup, messages);
      if (savedImages.length > 0) {
        process.stdout.write(`📷${savedImages.length} `);
      }

      // Re-get conv data to get current status
      const updatedList = await getConversationList(talkFrame);
      const current = updatedList[i] || conv;

      allData.push({
        name: current.name,
        status: current.isUnread ? 'unread' : 'read',
        lastMessageSnippet: current.lastMessage,
        messageCount: messages.length,
        messages: messages.slice(-50), // Last 50 messages max
        images: savedImages.length > 0 ? savedImages : undefined,
      });
    }

    console.log('\n');

    // 4. 保存
    const timestamp = new Date().toISOString().replace(/[:]/g, '-').substring(0, 19);
    const outputPath = join(DATA_DIR, `数据快照_${timestamp}.json`);
    writeFileSync(outputPath, JSON.stringify(allData, null, 2), 'utf-8');

    // 5. 生成摘要
    const totalMsg = allData.reduce((sum, c) => sum + c.messages.length, 0);
    const totalImg = allData.reduce((sum, c) => sum + (c.images?.length || 0), 0);
    const unreadCount = allData.filter(c => c.status === 'unread').length;
    console.log(`\n✅ 抓取完成`);
    console.log(`   会话: ${allData.length} | 总消息: ${totalMsg} | 图片: ${totalImg} | 未读: ${unreadCount}`);
    console.log(`   已保存: ${outputPath}`);

    return allData;
  } finally {
    await browser.close();
  }
}

async function frameEvaluateClickTab(frame, label) {
  return frame.evaluate((tabLabel) => {
    const tabs = document.querySelectorAll('.im-next-tabs-tab.list-tab-item');
    for (const tab of tabs) {
      if ((tab.textContent || '').trim() === tabLabel) {
        tab.click();
        return true;
      }
    }
    return false;
  }, label);
}

scrapeAll().catch(err => {
  console.error('\n❌ 抓取失败:', err.message);
  process.exit(1);
});

#!/usr/bin/env node

/**
 * 小满CRM — 完整看板报告 v2
 *
 * 生成排版更舒适的 Word 报告
 * TM 聊天 + 真实邮件（已过滤系统通知）
 *
 * 用法: node final-report.mjs
 */

import { readFileSync, writeFileSync, readdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, WidthType, BorderStyle, ShadingType, TableLayoutType, PageBreak,
} from 'docx';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..');

// ============================================================
// 调色板
// ============================================================
const COLORS = {
  primary: '1A237E',     // 深蓝（标题）
  secondary: '283593',   // 中蓝（子标题）
  accent: '5C6BC0',      // 浅蓝（强调）
  text: '333333',         // 正文
  gray: '888888',         // 辅助文字
  light: 'BBBBBB',        // 轻灰
  border: 'DDE1E6',       // 边框
  bg: 'F8F9FC',           // 全局背景
  white: 'FFFFFF',
  received: '1565C0',     // 客户消息蓝
  sent: '2E7D32',         // 我方消息绿
  email: '7B1FA2',        // 邮件紫色
  p0: 'C62828',           // P0 红
};

// ============================================================
// 工具函数
// ============================================================
function fmtDate(d) {
  d = new Date(d);
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')} ${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`;
}

function T(text, opts = {}) {
  return new TextRun({ text, size: opts.size || 20, color: opts.color || COLORS.text, bold: opts.bold, italics: opts.italics });
}

function P(runs, opts = {}) {
  return new Paragraph({
    children: Array.isArray(runs) ? runs : [runs],
    spacing: { before: opts.before || 0, after: opts.after || 80, line: opts.line || 360 },
    indent: opts.indent,
    border: opts.border,
    shading: opts.shading,
    alignment: opts.alignment,
  });
}

function spacer() {
  return P([T('', { size: 6 })], { before: 60, after: 60, border: { bottom: { style: BorderStyle.SINGLE, size: 1, color: COLORS.border } } });
}

// ============================================================
// 表格辅助
// ============================================================
function Cell(runs, opts = {}) {
  const children = Array.isArray(runs) ? runs : [runs];
  return new TableCell({
    children: [P(children, { alignment: opts.align })],
    width: opts.w ? { size: opts.w, type: WidthType.DXA } : undefined,
    shading: opts.bg ? { fill: opts.bg, type: ShadingType.CLEAR } : undefined,
    verticalAlign: 'center',
  });
}

function Row(cells) {
  return new TableRow({ children: cells });
}

// ============================================================
// 加载数据
// ============================================================
function loadData() {
  const files = readdirSync(DATA_DIR)
    .filter(f => f.startsWith('客户档案_') && f.endsWith('.json'))
    .sort().reverse();
  if (!files.length) throw new Error('请先运行 integrate.mjs');
  return JSON.parse(readFileSync(join(DATA_DIR, files[0]), 'utf-8'));
}

// ============================================================
// 构建文档
// ============================================================
async function build(data) {
  const { customers, stats, generatedAt, otherContacts } = data;
  const children = [];

  // ===================== COVER =====================
  children.push(
    P([T('小满CRM 客户完整档案', { size: 44, bold: true, color: COLORS.primary })], { alignment: AlignmentType.CENTER, before: 2000, after: 200 }),
    P([T('TM 聊天 + 邮件记录 · 按客户整合', { size: 24, color: COLORS.accent })], { alignment: AlignmentType.CENTER, after: 400 }),
    P([T(`生成时间: ${fmtDate(generatedAt)}`, { size: 20, color: COLORS.gray })], { alignment: AlignmentType.CENTER, after: 100 }),
    P([T(`客户: ${customers.length} 个  |  TM 消息: ${stats.totalTmMessages} 条  |  真实邮件: ${stats.totalEmails} 封  |  已过滤系统邮件: ${stats.filteredSystemEmails} 封`, { size: 20, color: COLORS.gray })], { alignment: AlignmentType.CENTER, after: 1200 }),
  );

  // ===================== 概览表 =====================
  children.push(
    P([T('一、数据概览', { size: 28, bold: true, color: COLORS.primary })], { before: 400, after: 200 }),
  );

  const overviewRows = [
    Row([Cell([T('指标', { bold: true, color: 'FFFFFF', size: 20 })], { bg: COLORS.primary, w: 3000 }), Cell([T('数量', { bold: true, color: 'FFFFFF', size: 20 })], { bg: COLORS.primary, w: 2000, align: AlignmentType.CENTER })]),
    Row([Cell([T('TM 会话', { size: 20 })], { bg: 'F5F5F5' }), Cell([T(String(customers.length), { size: 20 })], { bg: 'F5F5F5', align: AlignmentType.CENTER })]),
    Row([Cell([T('TM 消息', { size: 20 })]), Cell([T(String(stats.totalTmMessages), { size: 20 })], { align: AlignmentType.CENTER })]),
    Row([Cell([T('TM 图片', { size: 20 })], { bg: 'F5F5F5' }), Cell([T(String(stats.totalTmImages), { size: 20 })], { bg: 'F5F5F5', align: AlignmentType.CENTER })]),
    Row([Cell([T('真实往来邮件', { size: 20 })]), Cell([T(String(stats.totalEmails), { size: 20 })], { align: AlignmentType.CENTER })]),
    Row([Cell([T('邮件图片', { size: 20 })], { bg: 'F5F5F5' }), Cell([T(String(stats.totalEmailImages), { size: 20 })], { bg: 'F5F5F5', align: AlignmentType.CENTER })]),
    Row([Cell([T('已过滤系统通知', { size: 18, color: COLORS.gray })]), Cell([T(String(stats.filteredSystemEmails), { size: 18, color: COLORS.gray })], { align: AlignmentType.CENTER })]),
  ];

  children.push(
    new Table({ rows: overviewRows, width: { size: 100, type: WidthType.PERCENTAGE }, layout: TableLayoutType.FIXED }),
    P([], { after: 400 }),
  );

  // ===================== 客户档案 =====================
  children.push(
    P([T('二、客户详细档案', { size: 28, bold: true, color: COLORS.primary })], { before: 200, after: 300 }),
  );

  for (let i = 0; i < customers.length; i++) {
    const c = customers[i];
    const cat = c.classification?.categoryId || '—';

    // 客户标题栏（带背景色）
    children.push(
      P([
        T(`${i + 1}. ${c.name}`, { size: 26, bold: true, color: COLORS.secondary }),
        T(`  [${cat}]`, { size: 20, color: COLORS.gray }),
        T(`  TM:${c.tm.messageCount}条 | 邮件:${c.emails.total}封`, { size: 18, color: COLORS.gray }),
      ], {
        before: 200, after: 100,
        shading: { fill: 'EDE7F6', type: ShadingType.CLEAR },
        border: { left: { style: BorderStyle.SINGLE, size: 12, color: COLORS.accent } },
        indent: { left: 200 },
      }),
    );

    // ---- TM 消息 ----
    if (c.tm.messages.length > 0) {
      children.push(
        P([T('📩 TM 聊天记录', { size: 22, bold: true, color: COLORS.received })], { before: 200, after: 100 }),
      );

      // 只显示最近 8 条
      const msgs = c.tm.messages.slice(-8);
      for (const msg of msgs) {
        const isReceived = msg.side === 'received';
        const prefix = isReceived ? '客户' : '我方';
        const color = isReceived ? COLORS.received : COLORS.sent;
        const bg = isReceived ? 'E3F2FD' : 'E8F5E9';
        const borderColor = isReceived ? '90CAF9' : 'A5D6A7';
        const snippet = msg.content.substring(0, 500);

        children.push(
          P([
            T(`${prefix}: `, { size: 18, bold: true, color }),
            T(snippet, { size: 18, color: '444444' }),
          ], {
            before: 60, after: 40,
            indent: { left: 400 },
            shading: { fill: bg, type: ShadingType.CLEAR },
            border: { left: { style: BorderStyle.SINGLE, size: 6, color: borderColor } },
          }),
        );
      }
      if (c.tm.messages.length > 8) {
        children.push(P([T(`  …… 共 ${c.tm.messages.length} 条`, { size: 16, color: COLORS.gray, italics: true })], { indent: { left: 400 }, after: 40 }));
      }

      // TM 图片
      if (c.tm.images.length > 0) {
        children.push(P([T(`📷 ${c.tm.images.length} 张聊天图片`, { size: 17, color: COLORS.gray })], { indent: { left: 400 }, after: 60 }));
      }
    } else {
      children.push(P([T('无 TM 聊天记录', { size: 17, color: COLORS.gray, italics: true })], { indent: { left: 400 }, after: 40 }));
    }

    // ---- 邮件记录 ----
    const hasEmail = c.emails.inbox.length > 0 || c.emails.sent.length > 0;
    if (hasEmail) {
      children.push(P([], { after: 100 }));
      children.push(
        P([T('📧 往来邮件', { size: 22, bold: true, color: COLORS.email })], { before: 100, after: 100 }),
      );

      for (const mail of c.emails.sent) {
        // 邮件头
        children.push(
          P([
            T('📤 发送 ', { size: 18, color: COLORS.sent, bold: true }),
            T(mail.subject, { size: 19, bold: true, color: '333333' }),
          ], { indent: { left: 400 }, after: 20 }),
          P([
            T(`收件人: ${mail.to}    ${mail.time}`, { size: 16, color: COLORS.gray }),
          ], { indent: { left: 500 }, after: 20 }),
        );

        // 邮件正文
        if (mail.body) {
          const bodyLines = mail.body.replace(/\n{3,}/g, '\n\n').substring(0, 1500);
          const lines = bodyLines.split('\n').filter(Boolean);
          for (const line of lines.slice(0, 20)) {
            children.push(
              P([T(line.trim(), { size: 17, color: '555555' })], { indent: { left: 600 }, after: 12 }),
            );
          }
          if (bodyLines.length > 1500) {
            children.push(P([T('……（内容较长已截断）', { size: 15, color: COLORS.light, italics: true })], { indent: { left: 600 }, after: 20 }));
          }
        }

        if (mail.images?.length > 0) {
          children.push(P([T(`🖼️ 含 ${mail.images.length} 张图片`, { size: 16, color: COLORS.gray })], { indent: { left: 600 }, after: 40 }));
        }
      }

      for (const mail of c.emails.inbox) {
        children.push(
          P([
            T('📥 收到 ', { size: 18, color: COLORS.received, bold: true }),
            T(mail.subject, { size: 19, bold: true, color: '333333' }),
          ], { indent: { left: 400 }, after: 20 }),
          P([
            T(`${mail.time}`, { size: 16, color: COLORS.gray }),
          ], { indent: { left: 500 }, after: 20 }),
        );
        if (mail.body) {
          const lines = mail.body.replace(/\n{3,}/g, '\n\n').split('\n').filter(Boolean).slice(0, 15);
          for (const line of lines) {
            children.push(
              P([T(line.trim(), { size: 17, color: '555555' })], { indent: { left: 600 }, after: 12 }),
            );
          }
        }
        if (mail.images?.length > 0) {
          children.push(P([T(`🖼️ 含 ${mail.images.length} 张图片`, { size: 16, color: COLORS.gray })], { indent: { left: 600 }, after: 40 }));
        }
      }
    } else {
      children.push(P([T('无往来邮件记录', { size: 17, color: COLORS.gray, italics: true })], { indent: { left: 400 }, after: 40 }));
    }

    children.push(spacer());
  }

  // ===================== 其他业务联系人 =====================
  if (otherContacts && otherContacts.length > 0) {
    children.push(
      P([T('三、其他邮件业务联系人', { size: 28, bold: true, color: COLORS.primary })], { before: 400, after: 200 }),
      P([T('以下联系人有邮件往来但不在当前 TM 会话列表中：', { size: 18, color: COLORS.gray })], { after: 200 }),
    );

    for (const oc of otherContacts) {
      children.push(
        P([
          T(oc.name, { size: 22, bold: true, color: COLORS.secondary }),
          T(`  ${oc.time}`, { size: 16, color: COLORS.gray }),
        ], { before: 200, after: 60 }),
        P([T(oc.subject, { size: 19, bold: true, color: '444444' })], { indent: { left: 300 }, after: 20 }),
      );
      if (oc.body) {
        const lines = oc.body.replace(/\n{3,}/g, '\n\n').split('\n').filter(Boolean).slice(0, 15);
        for (const line of lines) {
          children.push(P([T(line.trim(), { size: 17, color: '555555' })], { indent: { left: 400 }, after: 12 }));
        }
      }
      if (oc.images?.length > 0) {
        children.push(P([T(`🖼️ 含 ${oc.images.length} 张图片`, { size: 16, color: COLORS.gray })], { indent: { left: 400 }, after: 20 }));
      }
      children.push(P([], { after: 80 }));
    }
  }

  // ===================== 页脚 =====================
  children.push(
    P([], { before: 600 }),
    P([T('小星星服饰 · 小满CRM自动生成', { size: 16, color: 'BDBDBD' })], { alignment: AlignmentType.CENTER }),
    P([T(fmtDate(generatedAt), { size: 14, color: 'BDBDBD' })], { alignment: AlignmentType.CENTER }),
  );

  return new Document({
    creator: '小满CRM助手',
    title: '小满CRM客户完整档案',
    styles: { default: { document: { run: { size: 20, font: '微软雅黑' } } } },
    sections: [{ children }],
  });
}

// ============================================================
// 主流程
// ============================================================
async function main() {
  console.log('📂 加载整合数据...');
  const data = loadData();
  console.log(`   客户: ${data.customers.length} 个`);

  console.log('📝 生成完整看板报告 v2...');
  const doc = await build(data);
  const ts = new Date().toISOString().replace(/[:]/g, '-').substring(0, 19);
  const out = join(DATA_DIR, `完整档案_${ts}.docx`);
  writeFileSync(out, await Packer.toBuffer(doc));
  console.log(`   已保存: ${out}\n✅ 完成！`);
}

main().catch(err => { console.error(`\n❌ 错误: ${err.message}`); process.exit(1); });

