#!/usr/bin/env node

/**
 * 小满CRM — 客户执行方案生成器
 * 输出精美排版的 Word 文档到桌面
 */

import { readFileSync, writeFileSync, readdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, WidthType, BorderStyle, ShadingType, TableLayoutType,
} from 'docx';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DATA_DIR = join(__dirname, '..');
const DESKTOP = 'C:/Users/Administrator/Desktop';

// ============================================================
// 调色板 — 阅读舒适为首要目标
// ============================================================
const C = {
  ink: '1A1A1A',        // 正文
  soft: '555555',       // 辅助文字
  light: '999999',      // 轻灰
  line: 'D9D9D9',       // 分隔线

  accent: '1A56DB',     // 主强调蓝
  accentBg: 'EEF2FF',   // 蓝底

  red: 'C92A2A',        // P0 紧急
  redBg: 'FFF5F5',      // P0 底色
  orange: 'D9480F',     // 高优
  orangeBg: 'FFF4EC',   // 高优底色
  yellow: 'B8860B',     // 关注
  yellowBg: 'FFFBE6',   // 关注底色

  green: '2B8A3E',      // 已处理
  greenBg: 'EBFBEE',
  purple: '7950F2',
  teal: '0C8599',

  white: 'FFFFFF',
  bg: 'FAFBFD',
};

// ============================================================
// 排版辅助
// ============================================================

function T(text, opts = {}) {
  return new TextRun({
    text,
    size: opts.size || 21,
    color: opts.color || C.ink,
    bold: opts.bold,
    italics: opts.italics,
    font: opts.font || 'Microsoft YaHei',
  });
}

function P(runs, opts = {}) {
  return new Paragraph({
    children: Array.isArray(runs) ? runs : [runs],
    spacing: { before: opts.before || 0, after: opts.after || 60, line: opts.line || 340 },
    indent: opts.indent,
    alignment: opts.alignment || AlignmentType.LEFT,
    border: opts.border,
    shading: opts.shading,
  });
}

function Spacer(h = 6) {
  return new Paragraph({ spacing: { before: h, after: h } });
}

function Divider() {
  return new Paragraph({
    children: [],
    spacing: { before: 120, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 1, color: C.line } },
  });
}

function Section(title, color) {
  return new Paragraph({
    children: [T(title, { size: 30, bold: true, color: color || C.accent })],
    spacing: { before: 360, after: 160 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 3, color: color || C.accent } },
  });
}

function Card(title, contents, { color = C.accent, bgColor = C.accentBg, icon = '' } = {}) {
  const paragraphs = [];

  // 卡片标题
  paragraphs.push(new Paragraph({
    children: [T((icon ? icon + ' ' : '') + title, { size: 24, bold: true, color })],
    spacing: { before: 200, after: 80 },
    shading: { fill: bgColor, type: ShadingType.CLEAR },
    indent: { left: 200 },
    border: { left: { style: BorderStyle.SINGLE, size: 8, color } },
  }));

  // 卡片内容
  for (const item of contents) {
    if (item.type === 'info') {
      paragraphs.push(new Paragraph({
        children: [
          T(item.label + '：', { size: 19, color: C.soft, bold: true }),
          T(item.value, { size: 19, color: C.ink }),
        ],
        spacing: { after: 30 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'msg') {
      const sideLabel = item.side === 'received' ? '📩 客户' : '📤 我方';
      const sideColor = item.side === 'received' ? C.purple : C.teal;
      paragraphs.push(new Paragraph({
        children: [
          T(sideLabel + '：', { size: 18, bold: true, color: sideColor }),
          T(item.text, { size: 18, color: C.soft }),
        ],
        spacing: { after: 20 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'action') {
      paragraphs.push(new Paragraph({
        children: [T('▸ ' + item.text, { size: 19, color: C.ink })],
        spacing: { before: 40, after: 20 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'reply') {
      paragraphs.push(new Paragraph({
        children: [T(item.text, { size: 18, color: C.ink, italics: true })],
        spacing: { before: 30, after: 40 },
        indent: { left: 560 },
        shading: { fill: 'F8F9FA', type: ShadingType.CLEAR },
        border: { left: { style: BorderStyle.SINGLE, size: 4, color: C.line } },
      }));
    } else if (item.type === 'highlight') {
      paragraphs.push(new Paragraph({
        children: [T('⚠ ' + item.text, { size: 18, color: C.red, bold: true })],
        spacing: { before: 40, after: 40 },
        indent: { left: 500 },
      }));
    }
  }

  return paragraphs;
}

// ============================================================
// 客户分析数据（硬编码 — 基于最新数据快照的分析结果）
// ============================================================

const actionPlan = {
  generatedAt: new Date(),
  summary: {
    totalCustomers: 20,
    p0Urgent: 13,
    p1High: 3,
    p2Normal: 2,
    p3Low: 2,
  },
};

// ============================================================
// 构建文档
// ============================================================
async function build() {
  const children = [];
  const now = actionPlan.generatedAt;

  // ==================== 封面 ====================
  children.push(new Paragraph({ spacing: { before: 1200 } }));
  children.push(
    new Paragraph({
      children: [T('小满CRM · 客户执行方案', { size: 48, bold: true, color: C.accent })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 120 },
    }),
    new Paragraph({
      children: [T('待处理客户回复建议 & 后续动作', { size: 26, color: C.soft })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 300 },
    }),
    new Paragraph({
      children: [T('小星星服饰 · 阿里巴巴国际站', { size: 20, color: C.light })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 60 },
    }),
    new Paragraph({
      children: [T(`${now.getFullYear()}年${now.getMonth() + 1}月${now.getDate()}日  生成`, { size: 20, color: C.light })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 600 },
    }),
  );

  // ==================== 一、看板概览 ====================
  children.push(Section('一、看板概览', C.accent));

  // 统计卡片
  const statItems = [
    { label: '总会话', value: '20', sub: '个客户', color: C.accent, bg: C.accentBg },
    { label: 'P0 紧急', value: '13', sub: '今日必须处理', color: C.red, bg: C.redBg },
    { label: 'P1 重要', value: '3', sub: '48h内处理', color: C.orange, bg: C.orangeBg },
    { label: 'P2/P3 常规', value: '4', sub: '本周处理', color: C.yellow, bg: C.yellowBg },
  ];

  children.push(
    new Table({
      rows: [
        new TableRow({
          children: statItems.map(s =>
            new TableCell({
              children: [
                new Paragraph({
                  children: [T(s.value, { size: 36, bold: true, color: s.color })],
                  alignment: AlignmentType.CENTER,
                  spacing: { after: 20 },
                }),
                new Paragraph({
                  children: [T(s.label, { size: 20, bold: true, color: C.ink })],
                  alignment: AlignmentType.CENTER,
                  spacing: { after: 10 },
                }),
                new Paragraph({
                  children: [T(s.sub, { size: 16, color: C.light })],
                  alignment: AlignmentType.CENTER,
                }),
              ],
              shading: { fill: s.bg, type: ShadingType.CLEAR },
              width: { size: 2200, type: WidthType.DXA },
              margins: { top: 200, bottom: 200 },
            })
          ),
        }),
      ],
      width: { size: 100, type: WidthType.PERCENTAGE },
      layout: TableLayoutType.FIXED,
    }),
  );

  children.push(Spacer(80));

  // 分类明细表
  children.push(
    new Paragraph({
      children: [T('客户分类明细', { size: 22, bold: true, color: C.ink })],
      spacing: { before: 200, after: 120 },
    }),
  );

  const categoryRows = [
    ['🔴 待回复', '6人', 'TheodoraAdelaide Mahe, User name(Fathima), Ahmed Darrat, zainab Babesets, Aula Alsaad, Adm Reda', C.red],
    ['🟠 待报价', '5人', 'Cindy Nadal, fernande Pochette, Krisgel Igros, Sifa Vano, Regina Kabanda', C.orange],
    ['⚠️ 分类需修正', '2人', 'rehema kiseyu(实为样品询盘), azaan ss(实为询价)', C.red],
    ['🟡 待付款/确认', '2人', 'amer ly, Susuanna ParkerAdentwi', C.yellow],
    ['🔵 低活跃', '5人', 'Jemima Piema, Assiatou Barry, Sayfullaeva Shahnoza, Lohgah Sharon, 同行推销', C.light],
  ];

  const headerRow = new TableRow({
    tableHeader: true,
    children: [
      new TableCell({
        children: [new Paragraph({ children: [T('状态', { size: 19, bold: true, color: C.white })] })],
        shading: { fill: C.accent, type: ShadingType.CLEAR },
        width: { size: 1600, type: WidthType.DXA },
        margins: { top: 80, bottom: 80 },
      }),
      new TableCell({
        children: [new Paragraph({ children: [T('数量', { size: 19, bold: true, color: C.white })], alignment: AlignmentType.CENTER })],
        shading: { fill: C.accent, type: ShadingType.CLEAR },
        width: { size: 800, type: WidthType.DXA },
        margins: { top: 80, bottom: 80 },
      }),
      new TableCell({
        children: [new Paragraph({ children: [T('客户', { size: 19, bold: true, color: C.white })] })],
        shading: { fill: C.accent, type: ShadingType.CLEAR },
        width: { size: 6400, type: WidthType.DXA },
        margins: { top: 80, bottom: 80 },
      }),
    ],
  });

  const dataRows = categoryRows.map((r, i) =>
    new TableRow({
      children: [
        new TableCell({
          children: [new Paragraph({ children: [T(r[0], { size: 18, bold: true, color: r[3] })] })],
          margins: { top: 60, bottom: 60 },
          width: { size: 1600, type: WidthType.DXA },
        }),
        new TableCell({
          children: [new Paragraph({ children: [T(r[1], { size: 18, color: C.ink })], alignment: AlignmentType.CENTER })],
          width: { size: 800, type: WidthType.DXA },
        }),
        new TableCell({
          children: [new Paragraph({ children: [T(r[2], { size: 17, color: C.soft })] })],
          width: { size: 6400, type: WidthType.DXA },
        }),
      ],
    })
  );

  children.push(
    new Table({
      rows: [headerRow, ...dataRows],
      width: { size: 100, type: WidthType.PERCENTAGE },
      layout: TableLayoutType.FIXED,
    }),
  );

  // ==================== 二、今日紧急处理 ====================
  children.push(Divider());
  children.push(Section('二、今日紧急处理（P0）', C.red));

  // --- amer ly ---
  children.push(...Card('1. amer ly  |  伊拉克  |  🟡待付款  |  S级 — 今日跟进', [
    { type: 'info', label: '当前状态', value: '报价已发（$106.4 + $157运费 DAP），客户给了物流地址，我方最后发言。客户之前催过"هل أكملت؟"（弄好了吗？），说明有紧迫感。客户要的是现货！' },
    { type: 'info', label: '产品', value: 'Summer Boys Outfit Set, 7色×4尺码=28件, $3.8/pc' },
    { type: 'info', label: '物流', value: '伊拉克Nasiriyah, DHL约$157, 7-9天' },
    { type: 'info', label: '判断', value: '客户要现货（ready stock），不是定制生产。拖延可能是在比较运费/总价，或者付款方式有顾虑' },
    { type: 'action', text: '今日行动：确认现货库存，直接问付款方式偏好，不要提"生产"二字' },
    { type: 'reply', text: '【建议回复（阿拉伯语）】\n\nمرحباً، أردت فقط المتابعة معك بخصوص الطلب.\n\nالمنتجات الـ 28 قطعة (7 ألوان × 4 مقاسات) جاهزة في المخزون ويمكن شحنها فور استلام الدفع. الشحن إلى الناصرية عبر DHL يستغرق 7-9 أيام.\n\nهل تفضل الدفع عن طريق:\n- TT (تحويل بنكي)؟\n- أم Alibaba Trade Assurance؟\n\nبمجرد تأكيد طريقة الدفع، سأرسل لك الفاتورة النهائية للدفع مباشرة.' },
  ], { color: C.red, bgColor: C.redBg, icon: '🔴' }));

  // --- azaan ss ---
  children.push(...Card('2. azaan ss  |  国家未知  |  ⚠️询价未回复  |  S级 — 今日必须给价格', [
    { type: 'info', 'label': '当前状态', value: '客户反复问"How much"，数量200pcs mix sizes。我方两次说"问经理确认价格"，但从未给出实际报价。客户最后一次消息仍是"How much"' },
    { type: 'info', 'label': '产品', value: 'Custom Kids Set 2 Pcs 100 Cotton Canvas Cartoon Print — 2款产品成本相同，1688拿货成本15.2元/pc' },
    { type: 'info', 'label': '定价', value: '成本15.2÷0.6÷6.8=$3.72，报价$3.80/pc（覆盖国际站运营成本）' },
    { type: 'highlight', text: '我方说了两次"问经理"但没给价格，客户已经问了第三次。再拖客户就走了！' },
    { type: 'action', text: '今日行动：立即报$3.80/pc，200pcs FOB，不要等。说明工厂BSCI/迪士尼资质支撑品质' },
    { type: 'reply', text: '【建议回复（英语）】\n\nHi! Sorry for the wait — I have the pricing ready for you.\n\nFor the Kids Cotton Canvas Set (200pcs mixed sizes, both styles same price):\n- Unit price: $3.80/pc FOB\n- Total: $760 for 200pcs\n- Lead time: 15-20 days after payment\n- Sample: $3.80/pc + shipping (deductible from bulk order)\n\nWe\'re a BSCI-certified, Disney-approved factory — quality is guaranteed. Our pricing includes full quality control and international trade assurance.\n\nShipping cost depends on your city — could you share your delivery address?' },
  ], { color: C.red, bgColor: C.redBg, icon: '🔴' }));

  // --- zainab Babesets ---
  children.push(...Card('3. zainab Babesets  |  伊拉克  |  🔴待回复  |  A级', [
    { type: 'info', 'label': '当前状态', value: '客户发了多个产品卡片，我方发过价格表和节日问候。客户最后消息："هل من الممكن ان اطلع على العروض"（我能看看报价吗？）— 但这条消息之后我方没有回复！' },
    { type: 'info', 'label': '产品', value: 'Custom Kids Set 2 Pcs Cotton Canvas + Children Cotton Vest Set + 2-Piece Cartoon Shorts Set' },
    { type: 'highlight', text: '客户主动要报价，我方没有直接回应这个请求。分类为awaiting_reply B级太低了，应是A级。' },
    { type: 'action', text: '今日行动：直接回复客户要的报价信息，附上3个产品的单价表' },
    { type: 'reply', text: '【建议回复（阿拉伯语）】\n\nنعم بالطبع! إليك الأسعار للمنتجات التي استفسرت عنها:\n\n1. طقم أطفال مكون من قطعتين من القطن (Custom Kids Set): $2.15/قطعة\n2. طقم فيست قطني للأطفال (Cotton Vest Set): $2.50/قطعة  \n3. طقم شورت كرتوني (Cartoon Shorts Set): $1.80/قطعة\n\nالحد الأدنى للطلب: 500 قطعة لكل تصميم (يمكن مزج الألوان والمقاسات)\nالشحن: أحتاج عنوان التوصيل في العراق لحساب التكلفة بدقة\n\nأي من هذه المنتجات يناسب احتياجاتك أكثر؟' },
