#!/usr/bin/env node

/**
 * 小满CRM — 客户执行方案生成器
 * 输出精美排版的 Word 文档到桌面
 * v2 — 基于完整对话数据逐条验证，四段式结构（诊断/策略/话术/触发）
 */

import { readFileSync, writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, WidthType, BorderStyle, ShadingType, TableLayoutType,
} from 'docx';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DESKTOP = 'C:/Users/Administrator/Desktop';

// ============================================================
// 调色板
// ============================================================
const C = {
  ink: '1A1A1A',
  soft: '555555',
  light: '999999',
  line: 'D9D9D9',
  accent: '1A56DB',
  accentBg: 'EEF2FF',
  red: 'C92A2A',
  redBg: 'FFF5F5',
  orange: 'D9480F',
  orangeBg: 'FFF4EC',
  yellow: 'B8860B',
  yellowBg: 'FFFBE6',
  green: '2B8A3E',
  greenBg: 'EBFBEE',
  purple: '7950F2',
  teal: '0C8599',
  white: 'FFFFFF',
  bg: 'FAFBFD',
};

// ============================================================
// 排版辅助
// ============================================================
function T(text, opts = {}) {
  return new TextRun({
    text,
    size: opts.size || 21,
    color: opts.color || C.ink,
    bold: opts.bold,
    italics: opts.italics,
    font: opts.font || 'Microsoft YaHei',
  });
}

function P(runs, opts = {}) {
  return new Paragraph({
    children: Array.isArray(runs) ? runs : [runs],
    spacing: { before: opts.before || 0, after: opts.after || 60, line: opts.line || 340 },
    indent: opts.indent,
    alignment: opts.alignment || AlignmentType.LEFT,
    border: opts.border,
    shading: opts.shading,
  });
}

function Spacer(h = 6) {
  return new Paragraph({ spacing: { before: h, after: h } });
}

function Divider() {
  return new Paragraph({
    children: [],
    spacing: { before: 120, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 1, color: C.line } },
  });
}

function Section(title, color) {
  return new Paragraph({
    children: [T(title, { size: 30, bold: true, color: color || C.accent })],
    spacing: { before: 360, after: 160 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 3, color: color || C.accent } },
  });
}

function Card(title, contents, { color = C.accent, bgColor = C.accentBg, icon = '' } = {}) {
  const paragraphs = [];
  paragraphs.push(new Paragraph({
    children: [T((icon ? icon + ' ' : '') + title, { size: 24, bold: true, color })],
    spacing: { before: 200, after: 80 },
    shading: { fill: bgColor, type: ShadingType.CLEAR },
    indent: { left: 200 },
    border: { left: { style: BorderStyle.SINGLE, size: 8, color } },
  }));
  for (const item of contents) {
    if (item.type === 'info') {
      paragraphs.push(new Paragraph({
        children: [
          T(item.label + '：', { size: 19, color: C.soft, bold: true }),
          T(item.value, { size: 19, color: C.ink }),
        ],
        spacing: { after: 30 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'diagnosis') {
      paragraphs.push(new Paragraph({
        children: [T('诊断｜' + item.text, { size: 19, color: C.ink })],
        spacing: { before: 60, after: 30 },
        indent: { left: 500 },
        border: { left: { style: BorderStyle.SINGLE, size: 3, color: C.accent } },
      }));
    } else if (item.type === 'strategy') {
      paragraphs.push(new Paragraph({
        children: [T('策略｜' + item.text, { size: 19, color: C.ink })],
        spacing: { before: 40, after: 30 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'reply') {
      paragraphs.push(new Paragraph({
        children: [
          T('回复话术：', { size: 18, bold: true, color: C.green }),
          T(item.text, { size: 18, color: C.ink, italics: true }),
        ],
        spacing: { before: 30, after: 30 },
        indent: { left: 560 },
        shading: { fill: 'F8F9FA', type: ShadingType.CLEAR },
        border: { left: { style: BorderStyle.SINGLE, size: 4, color: C.green } },
      }));
    } else if (item.type === 'trigger') {
      paragraphs.push(new Paragraph({
        children: [T('触发｜' + item.text, { size: 18, color: C.orange })],
        spacing: { before: 20, after: 20 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'highlight') {
      paragraphs.push(new Paragraph({
        children: [T('⚠ ' + item.text, { size: 18, color: C.red, bold: true })],
        spacing: { before: 20, after: 20 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'action') {
      paragraphs.push(new Paragraph({
        children: [T('▸ ' + item.text, { size: 19, color: C.ink })],
        spacing: { before: 40, after: 20 },
        indent: { left: 500 },
      }));
    }
  }
  return paragraphs;
}

// ============================================================
// 构建文档
// ============================================================
async function build() {
  const children = [];
  const now = new Date();

  // ==================== 封面 ====================
  children.push(new Paragraph({ spacing: { before: 1200 } }));
  children.push(
    new Paragraph({
      children: [T('小满CRM · 客户执行方案', { size: 48, bold: true, color: C.accent })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 120 },
    }),
    new Paragraph({
      children: [T('专业客户跟进策略 & 回复话术', { size: 26, color: C.soft })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 300 },
    }),
    new Paragraph({
      children: [T('小星星服饰 · 阿里巴巴国际站 B2B', { size: 20, color: C.light })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 60 },
    }),
    new Paragraph({
      children: [T(`${now.getFullYear()}年${now.getMonth() + 1}月${now.getDate()}日  生成`, { size: 20, color: C.light })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 600 },
    }),
  );

  // ==================== 一、看板概览 ====================
  children.push(Section('一、看板概览', C.accent));

  const statItems = [
    { label: '总客户', value: '22', sub: '待处理会话', color: C.accent, bg: C.accentBg },
    { label: 'P0 紧急', value: '5', sub: '今日必须处理', color: C.red, bg: C.redBg },
    { label: 'P1 重要', value: '5', sub: '48h内处理', color: C.orange, bg: C.orangeBg },
    { label: 'P2/P3 常规', value: '12', sub: '本周处理', color: C.yellow, bg: C.yellowBg },
  ];

  children.push(
    new Table({
      rows: [
        new TableRow({
          children: statItems.map(s =>
            new TableCell({
              children: [
                new Paragraph({
                  children: [T(s.value, { size: 36, bold: true, color: s.color })],
                  alignment: AlignmentType.CENTER,
                  spacing: { after: 20 },
                }),
                new Paragraph({
                  children: [T(s.label, { size: 20, bold: true, color: C.ink })],
                  alignment: AlignmentType.CENTER,
                  spacing: { after: 10 },
                }),
                new Paragraph({
                  children: [T(s.sub, { size: 16, color: C.light })],
                  alignment: AlignmentType.CENTER,
                }),
              ],
              shading: { fill: s.bg, type: ShadingType.CLEAR },
              width: { size: 2200, type: WidthType.DXA },
              margins: { top: 200, bottom: 200 },
            })
          ),
        }),
      ],
      width: { size: 100, type: WidthType.PERCENTAGE },
      layout: TableLayoutType.FIXED,
    }),
  );

  children.push(Spacer(80));

  children.push(
    new Paragraph({
      children: [T('客户分类明细', { size: 22, bold: true, color: C.ink })],
      spacing: { before: 200, after: 120 },
    }),
  );

  const headerRow = new TableRow({
    tableHeader: true,
    children: [
      new TableCell({
        children: [new Paragraph({ children: [T('状态', { size: 19, bold: true, color: C.white })] })],
        shading: { fill: C.accent, type: ShadingType.CLEAR },
        width: { size: 1600, type: WidthType.DXA },
        margins: { top: 80, bottom: 80 },
      }),
      new TableCell({
        children: [new Paragraph({ children: [T('数量', { size: 19, bold: true, color: C.white })], alignment: AlignmentType.CENTER })],
        shading: { fill: C.accent, type: ShadingType.CLEAR },
        width: { size: 800, type: WidthType.DXA },
      }),
      new TableCell({
        children: [new Paragraph({ children: [T('客户', { size: 19, bold: true, color: C.white })] })],
        shading: { fill: C.accent, type: ShadingType.CLEAR },
        width: { size: 6400, type: WidthType.DXA },
      }),
    ],
  });

  const categoryRows = [
    ['🔴 P0 今日紧急', '5人', 'amer ly, azaan ss, zainab Babesets, Amal Alamhrooqi(arshavin amoah), Ahmed Darrat', C.red],
    ['🟠 P1 48h内', '5人', 'Krisgel Igros, fernande Pochette, Aula Alsaad, Susuanna ParkerAdentwi, rehema kiseyu', C.orange],
    ['🟡 P2 本周内', '6人', 'Cindy Nadal, Sifa Vano, Regina Kabanda, Adm Reda, Sayfullaeva Shahnoza(AnneMarie Nsomp), maimouna cisse(Conteza Elias)', C.yellow],
    ['🔵 P3 低活跃', '6人', 'TheodoraAdelaide Mahe, Fathima, Jemima Piema, Assiatou Barry, Lohgah Sharon, 同行推销', C.light],
  ];

  children.push(
    new Table({
      rows: [headerRow, ...categoryRows.map(r =>
        new TableRow({
          children: [
            new TableCell({
              children: [new Paragraph({ children: [T(r[0], { size: 18, bold: true, color: r[3] })] })],
              margins: { top: 60, bottom: 60 },
              width: { size: 1600, type: WidthType.DXA },
            }),
            new TableCell({
              children: [new Paragraph({ children: [T(r[1], { size: 18, color: C.ink })], alignment: AlignmentType.CENTER })],
              width: { size: 800, type: WidthType.DXA },
            }),
            new TableCell({
              children: [new Paragraph({ children: [T(r[2], { size: 17, color: C.soft })] })],
              width: { size: 6400, type: WidthType.DXA },
            }),
          ],
        })
      )],
      width: { size: 100, type: WidthType.PERCENTAGE },
      layout: TableLayoutType.FIXED,
    }),
  );

  // ==================== 二、P0 今日紧急处理 ====================
  children.push(Divider());
  children.push(Section('二、P0 今日紧急处理', C.red));

  children.push(...Card('1. amer ly  |  伊拉克  |  S级  |  已报价·待确认付款', [
    { type: 'diagnosis', text: '已发完整报价：$3.80/pc×28件=$106.40，运费$157 DAP到伊拉克Nasiriyah，总价$263.40。客户给了物流地址，Apr 28催过"弄好了吗"，我方已发PI文件。客户要的是现货(ready stock)，7色×4码各1件，不是定制生产。当前卡点：客户可能在比价/犹豫运费较高/确认付款方式。' },
    { type: 'strategy', text: '客户主动催过进度说明有紧迫感。不要提"生产"只说"库存"。直接推进付款环节：给TT和Trade Assurance两个选项，发付款链接。如果$157是痛点，提供海运选项作对比（便宜但慢），让客户自己选。' },
    { type: 'reply', text: 'السلام عليكم! فقط متابعة بسيطة — الـ 28 قطعة (7 ألوان × 4 مقاسات) موجودة في المخزون وجاهزة للشحن فوراً. الشحن إلى الناصرية: • DHL Express: $157 (7-9 أيام) • شحن بحري: يحتاج استفسار (أرخص لكن أبطأ). هل تفضل الدفع عن طريق تحويل بنكي (TT) أم عن طريق ضمان التجارة (Trade Assurance)؟ بمجرد التأكيد، سأرسل الفاتورة النهائية مباشرة.' },
    { type: 'trigger', text: '1天不回复→发PI链接直接引导付款；3天不回复→轻量跟进"هل تحتاج أي تعديل على الطلب؟"' },
  ], { color: C.red, bgColor: C.redBg, icon: '🔴' }));

  children.push(...Card('2. azaan ss  |  国家未知  |  S级  |  已报价$3.80·客户沉默3天', [
    { type: 'diagnosis', text: '时间线：Apr 25客户问"How much"+发产品卡→Apr 26我方报$3.80-3.85（0-100pcs）+面料说明→我方追问"Where to ship?"→再发"Do you think I did something wrong?"。核心问题：①客户说的数量是"200 mix size"，我方却报0-100pcs价格，数量不匹配；②最后"我哪里做错了"太被动不专业；③客户3天未回复，需要重新激活。' },
    { type: 'strategy', text: '不道歉不追问，用价值信息重启对话。给出200pcs的明确价格（$3.80/pc FOB，$760 total），附产品品质背书和适用场景。如客户仍不复，3天后发实拍图/视频激活。' },
    { type: 'reply', text: 'Hi! Just wanted to share — we recently produced this kids cotton canvas set for a Middle East client, and the feedback on fabric quality has been excellent (100% combed cotton, pre-washed for softness). For your 200pcs mixed sizes: $3.80/pc FOB, total $760. Production: 15-20 days. I can send factory photos of this style if you\'d like. Which city would shipping be to? I\'ll calculate exact freight for you.' },
    { type: 'trigger', text: '3天不回复→发产品实拍图/视频；7天不回复→最后激活消息（新品推荐）' },
  ], { color: C.red, bgColor: C.redBg, icon: '🔴' }));

  children.push(...Card('3. zainab Babesets  |  伊拉克  |  A级  |  已多次报价·待确认产品方向', [
    { type: 'diagnosis', text: '时间跨度Apr 9-26，我方给出4个产品报价：$3.0(Custom Kids Set 2 Pcs)、$3.3(另一款)、$3.2/$2.9(批量价)。客户要"12件每种设计"+"批发价"+"不要单件"。我方最后消息是Apr 26价格更新(100-500pcs: $3.2和$2.9)，客户未回复。问题：给了太多价格但没推动"选一个继续"的动作，客户可能选择困难。' },
    { type: 'strategy', text: '帮客户简化选择——列出她看过的产品+价格+适用场景对比，让她选最感兴趣的。不要继续降价或加新产品。目标是从"浏览对比"推进到"选品报价"。' },
    { type: 'reply', text: 'مرحباً! فقط للتأكيد على العروض التي طلبتها: 1. طقم أطفال قطني (Custom Kids Set 2 Pcs): $3.0/قطعة (0-100) → $3.2/قطعة (100-500) — الأكثر مبيعاً. 2. طقم فيست قطني (Cotton Vest Set): $3.3/قطعة — مناسب للصيف. 3. طقم شورت كرتوني (Short Set): $2.9/قطعة (100-500) — الأقل سعراً. جميع المنتجات بمقاسات 80-120 سم وألوان متعددة. أي من هذه المنتجات هو الأكثر اهتماماً لك؟ سأرسل لك صوراً تفصيلية وأسعار الشحن إلى العراق فور تحديده.' },
    { type: 'trigger', text: '客户回复选择→发详细报价+运费+PI；3天不回复→发产品实拍图激活' },
  ], { color: C.red, bgColor: C.redBg, icon: '🔴' }));

  children.push(...Card('4. Amal Alamhrooqi  |  阿曼  |  S级  |  ⚠️UNREAD·最接近成交的客户', [
    { type: 'highlight', text: '上一轮方案完全遗漏！数据中名为arshavin amoah（Scraper Bug），实际发送者Amal Alamhrooqi，阿曼(Oman)，阿拉伯语，20条消息UNREAD。' },
    { type: 'diagnosis', text: '时间线：Apr 23报价$3.70×4+$59 DAP=$73.80→客户确认3件不同尺码→客户问"DDP到Oman是否可行"+"关税大概多少"+"有Oman客户吗"→我方查了货代说"No DDP available"→发了货运参考图。最新消息我方Apr 23的解释。UNREAD状态=客户有新未读回复。这是22个客户中最接近成交的——价格已接受，只卡在物流方式。' },
    { type: 'strategy', text: '核心目标：消除客户对自清关的恐惧。虽不能做DDP，但要给清晰的自清关指引（需要什么文件/大概流程/预计费用），让他觉得"自己清关也可以"。用"有其他Oman客户"的社交证明降低信任成本。直接推动创建订单。' },
    { type: 'reply', text: 'مرحباً آمال! بالنسبة للشحن إلى عمان، إليك توضيح: 1. DAP (نحن نغطي الشحن، وأنت تقومين بالتخليص الجمركي): $59، 7-9 أيام. 2. للتخليص الجمركي: عادةً بسيط — تحتاجين فقط الفاتورة التجارية وبوليصة الشحن التي سنوفرها. معظم عملائنا في الشرق الأوسط يقومون بذلك بسهولة. 3. التكاليف الجمركية التقريبية: حوالي 5-10% من قيمة الفاتورة. 4. نعم، لدينا عملاء في عمان ودول الخليج. هل يمكنني إنشاء الطلب لك الآن؟ سأرسل جميع مستندات الشحن اللازمة.' },
    { type: 'trigger', text: '客户确认DAP→立即创建订单；客户坚持DDP→联系货代确认可行性；3天不回复→电话/WhatsApp跟进' },
  ], { color: C.red, bgColor: C.redBg, icon: '🔴' }));

  children.push(...Card('5. Ahmed Darrat  |  阿拉伯国家  |  A级  |  沟通混乱·需重置对话', [
    { type: 'diagnosis', text: '时间线：客户发产品卡($3.40-3.80)+"hello frend"→我方欢迎模板→客户问"how much in rmb?"→我方问"定制还是现货"→客户发另一张图片→我方报价$5→客户说"i want this one"→我方说"This is not our product"→又发3-question模板。核心问题：①客户问了RMB价格（可能是中国贸易商），始终没得到回答；②先报价$5又说不是我们的产品，前后矛盾；③最后发模板显得无视客户具体问题。' },
    { type: 'strategy', text: '诚实承认混淆，确认客户到底要哪个产品（产品卡还是发的图片），直接回答RMB价格问题。用简短对话重启，不发模板。如果是中国贸易商→用中文沟通更方便。' },
    { type: 'reply', text: 'Hi friend, sorry for the confusion earlier! Let me clarify — I need to confirm: do you want the children pajama set from the product card, or the one in the picture you sent? They\'re different. For the pajama set: $3.60/pc (约¥25.9/pc). For the picture you sent — can you tell me the quantity? Also, are you buying for domestic China or for export? This helps me recommend the best option. 如果你方便用中文沟通，我也可以用中文和你聊。' },
    { type: 'trigger', text: '客户回复确认产品→直接报价；3天不回复→发我们有的类似产品推荐' },
  ], { color: C.red, bgColor: C.redBg, icon: '🔴' }));

  // ==================== 三、P1 48h内优先处理 ====================
  children.push(Divider());
  children.push(Section('三、P1 48h内优先处理', C.orange));

  children.push(...Card('6. Krisgel Igros  |  菲律宾  |  A级  |  已报价$3.75·缺运费信息', [
    { type: 'diagnosis', text: '客户发产品图片问"do you have this?"，说先estimate再上架，通常订20-30pcs。我方已报价$3.75/pc×10pcs=$37.50（Apr 26），说"运费还在查"。客户明确说"once I have an estimate cost already"才能上架——在等运费。当前卡点：没给运费，客户没法行动。' },
    { type: 'strategy', text: '立即补全运费信息。DHL到菲律宾小包裹约$35-45（5-7天）。给出30pcs的打包estimate（客户的typical order size），让她可以直接上架测试。在线卖家时间窗口很窄——上架前必须有价格。' },
    { type: 'reply', text: 'Hi! Here\'s the complete estimate for your page: • 10pcs: $37.50 + shipping ~$35 = ~$72.50 total • 30pcs (your usual): ~$112.50 + shipping ~$45 = ~$157.50 total. You can mix up to 5 different styles. All Disney-approved factory quality. Exact PI sent within 1 hour once you confirm styles. Want me to send our best-selling designs for the Philippine market?' },
    { type: 'trigger', text: '客户确认款式→1h内发PI；3天不回复→发畅销款图片刺激兴趣' },
