1	#!/usr/bin/env node
2	
3	/**
4	 * 小满CRM — 客户执行方案生成器
5	 * 输出精美排版的 Word 文档到桌面
6	 * v2 — 基于完整对话数据逐条验证，四段式结构（诊断/策略/话术/触发）
7	 */
8	
9	import { readFileSync, writeFileSync } from 'fs';
10	import { join, dirname } from 'path';
11	import { fileURLToPath } from 'url';
12	import {
13	  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
14	  AlignmentType, WidthType, BorderStyle, ShadingType, TableLayoutType,
15	} from 'docx';
16	
17	const __dirname = dirname(fileURLToPath(import.meta.url));
18	const DESKTOP = 'C:/Users/Administrator/Desktop';
19	
20	// ============================================================
