#!/usr/bin/env node

/**
 * 小满CRM — 客户执行方案生成器 v3
 * 输出专业排版的 Word 文档到桌面
 * 特点：中文话术 / 深度策略推演 / 多方案对比 / 风险预判
 */

import { writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, WidthType, BorderStyle, ShadingType, TableLayoutType,
} from 'docx';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DESKTOP = 'C:/Users/Administrator/Desktop';

// ============================================================
// 调色板 — 专业商务风格
// ============================================================
const C = {
  ink:      '1E1E1E',   // 正文黑
  soft:     '5C5C5C',   // 辅助灰
  light:    '8C8C8C',   // 轻灰
  line:     'D0D0D0',   // 分隔线
  accent:   '1A3A8A',   // 深蓝主强调
  accentBg: 'EDF1FA',   // 浅蓝底
  red:      'B71C1C',   // 警示红
  redBg:    'FFF0F0',   // 红底
  orange:   'C05A00',   // 高优橙
  orangeBg: 'FFF6ED',   // 橙底
  yellow:   '7A6300',   // 关注黄
  yellowBg: 'FFFCE8',   // 黄底
  green:    '1E6E2E',   // 行动绿
  greenBg:  'EDF7EF',   // 绿底
  purple:   '5C2D91',   // 紫色
  teal:     '0D6B6B',   // 青色
  white:    'FFFFFF',
  bg:       'FAFBFD',
  tableBg:  'F5F6FA',   // 表格底色
};

// ============================================================
// 排版工具
// ============================================================
const FONT = 'Microsoft YaHei';
const FONT_MONO = 'Consolas';

function T(text, opts = {}) {
  return new TextRun({
    text,
    size: opts.size || 21,
    color: opts.color || C.ink,
    bold: opts.bold || false,
    italics: opts.italics || false,
    font: opts.font || FONT,
  });
}

function P(runs, opts = {}) {
  return new Paragraph({
    children: Array.isArray(runs) ? runs : [runs],
    spacing: {
      before: opts.before || 0,
      after: opts.after ?? 80,
      line: opts.line || 360,
    },
    indent: opts.indent,
    alignment: opts.alignment || AlignmentType.LEFT,
    border: opts.border,
    shading: opts.shading,
  });
}

function Spacer(h = 8) {
  return new Paragraph({ spacing: { before: h, after: h } });
}

function Divider() {
  return new Paragraph({
    children: [],
    spacing: { before: 140, after: 140 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 1, color: C.line } },
  });
}

function Section(title, color) {
  return new Paragraph({
    children: [
      T(title, { size: 32, bold: true, color: color || C.accent }),
    ],
    spacing: { before: 400, after: 200 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: color || C.accent } },
  });
}

// 深度分析卡片 - 用于P0客户
function DeepCard(title, blocks, { color = C.accent, bgColor = C.accentBg } = {}) {
  const items = [];

  // 标题
  items.push(new Paragraph({
    children: [T(title, { size: 26, bold: true, color })],
    spacing: { before: 240, after: 100 },
    shading: { fill: bgColor, type: ShadingType.CLEAR },
    indent: { left: 200, right: 200 },
    border: {
      left: { style: BorderStyle.SINGLE, size: 10, color },
      bottom: { style: BorderStyle.SINGLE, size: 1, color: C.line },
    },
  }));

  for (const block of blocks) {
    if (block.type === 'section') {
      items.push(new Paragraph({
        children: [T('▌' + block.label, { size: 22, bold: true, color: C.ink })],
        spacing: { before: 120, after: 80 },
        indent: { left: 400 },
      }));
    } else if (block.type === 'text') {
      items.push(new Paragraph({
        children: [T(block.value, { size: 20, color: C.ink })],
        spacing: { after: 50 },
        indent: { left: 600 },
      }));
    } else if (block.type === 'compare') {
      // 方案对比表
      const rows = [
        new TableRow({
          tableHeader: true,
          children: ['方案', '做法', '风险', '判断'].map((h, i) =>
            new TableCell({
              children: [new Paragraph({
                children: [T(h, { size: 18, bold: true, color: C.white })],
                alignment: AlignmentType.CENTER,
              })],
              shading: { fill: color, type: ShadingType.CLEAR },
              width: { size: i === 0 ? 1200 : i === 3 ? 1000 : 2000, type: WidthType.DXA },
              margins: { top: 60, bottom: 60, left: 60, right: 60 },
            })
          ),
        }),
        ...block.options.map((opt, i) => {
          const bg = i % 2 === 0 ? C.white : C.tableBg;
          return new TableRow({
            children: [
              new TableCell({
                children: [new Paragraph({ children: [T(opt.name, { size: 18, bold: true, color: C.ink })], alignment: AlignmentType.CENTER })],
                shading: { fill: bg, type: ShadingType.CLEAR },
                margins: { top: 60, bottom: 60, left: 60, right: 60 },
              }),
              new TableCell({
                children: [new Paragraph({ children: [T(opt.actions, { size: 17, color: C.soft })] })],
                shading: { fill: bg, type: ShadingType.CLEAR },
                margins: { top: 60, bottom: 60, left: 60, right: 60 },
              }),
              new TableCell({
                children: [new Paragraph({ children: [T(opt.risks, { size: 17, color: C.red })] })],
                shading: { fill: bg, type: ShadingType.CLEAR },
                margins: { top: 60, bottom: 60, left: 60, right: 60 },
              }),
              new TableCell({
                children: [new Paragraph({ children: [T(opt.verdict, { size: 17, bold: true, color: opt.verdictColor || C.green })] })],
                shading: { fill: bg, type: ShadingType.CLEAR },
                margins: { top: 60, bottom: 60, left: 60, right: 60 },
              }),
            ],
          });
        }),
      ];

      items.push(
        new Table({
          rows,
          width: { size: 100, type: WidthType.PERCENTAGE },
          layout: TableLayoutType.FIXED,
        }),
      );
    } else if (block.type === 'strategy') {
      items.push(new Paragraph({
        children: [T('► 推荐策略：' + block.value, { size: 20, bold: true, color: C.green })],
        spacing: { before: 80, after: 60 },
        indent: { left: 600 },
      }));
    } else if (block.type === 'reply') {
      items.push(new Paragraph({
        children: [
          T('回复话术（中文）：', { size: 19, bold: true, color: C.green }),
        ],
        spacing: { before: 80, after: 40 },
        indent: { left: 400 },
      }));
      items.push(new Paragraph({
        children: [T(block.text, { size: 19, color: C.ink })],
        spacing: { after: 60 },
        indent: { left: 600, right: 200 },
        shading: { fill: C.greenBg, type: ShadingType.CLEAR },
        border: {
          left: { style: BorderStyle.SINGLE, size: 5, color: C.green },
          top: { style: BorderStyle.SINGLE, size: 1, color: C.line },
          bottom: { style: BorderStyle.SINGLE, size: 1, color: C.line },
          right: { style: BorderStyle.SINGLE, size: 1, color: C.line },
        },
      }));
    } else if (block.type === 'logic') {
      items.push(new Paragraph({
        children: [T(block.label, { size: 19, bold: true, color: C.purple })],
        spacing: { before: 60, after: 30 },
        indent: { left: 400 },
      }));
      items.push(new Paragraph({
        children: [T(block.text, { size: 18, color: C.soft })],
        spacing: { after: 40 },
        indent: { left: 600 },
      }));
    } else if (block.type === 'pricing') {
      items.push(new Paragraph({
        children: [T('定价推算：' + block.text, { size: 19, color: C.orange, italics: true })],
        spacing: { before: 40, after: 40 },
        indent: { left: 600 },
        shading: { fill: C.orangeBg, type: ShadingType.CLEAR },
      }));
    } else if (block.type === 'trigger') {
      items.push(new Paragraph({
        children: [T('⏎ 后续动作：' + block.text, { size: 19, bold: true, color: C.red })],
        spacing: { before: 80, after: 40 },
        indent: { left: 400 },
        border: { left: { style: BorderStyle.SINGLE, size: 4, color: C.red } },
      }));
    }
  }

  return items;
}

// 标准卡片 - 用于P1客户
function StdCard(title, contents, { color = C.accent, bgColor = C.accentBg } = {}) {
  const items = [];
  items.push(new Paragraph({
    children: [T(title, { size: 24, bold: true, color })],
    spacing: { before: 200, after: 80 },
    shading: { fill: bgColor, type: ShadingType.CLEAR },
    indent: { left: 200 },
    border: { left: { style: BorderStyle.SINGLE, size: 6, color } },
  }));

  for (const item of contents) {
    if (item.type === 'diag') {
      items.push(new Paragraph({
        children: [T('现状：' + item.text, { size: 19, color: C.ink })],
        spacing: { after: 40 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'strat') {
      items.push(new Paragraph({
        children: [T('策略：' + item.text, { size: 19, bold: true, color: C.ink })],
        spacing: { before: 40, after: 40 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'reply') {
      items.push(new Paragraph({
        children: [T('话术：', { size: 18, bold: true, color: C.green }), T(item.text, { size: 18, color: C.ink })],
        spacing: { after: 40 },
        indent: { left: 560 },
        shading: { fill: C.greenBg, type: ShadingType.CLEAR },
        border: { left: { style: BorderStyle.SINGLE, size: 3, color: C.green } },
      }));
    } else if (item.type === 'trigger') {
      items.push(new Paragraph({
        children: [T('触发：' + item.text, { size: 18, color: C.orange })],
        spacing: { after: 30 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'warn') {
      items.push(new Paragraph({
        children: [T('注意：' + item.text, { size: 18, color: C.red, bold: true })],
        spacing: { before: 20, after: 20 },
        indent: { left: 500 },
      }));
    }
  }
  return items;
}


// ============================================================
// 构建文档
// ============================================================
async function build() {
  const children = [];
  const now = new Date();

  // ==================== 封面 ====================
  children.push(new Paragraph({ spacing: { before: 1400 } }));
  children.push(
    new Paragraph({
      children: [
        T('小满CRM', { size: 30, color: C.light }),
      ],
      alignment: AlignmentType.CENTER,
      spacing: { after: 60 },
    }),
    new Paragraph({
      children: [
        T('客户执行方案', { size: 52, bold: true, color: C.accent }),
      ],
      alignment: AlignmentType.CENTER,
      spacing: { after: 160 },
    }),
    new Paragraph({
      children: [T('专业跟进策略 · 博弈推演 · 回复话术', { size: 24, color: C.soft })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 360 },
    }),
    new Paragraph({
      children: [T('小星星服饰  ·  阿里巴巴国际站 B2B', { size: 19, color: C.light })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 40 },
    }),
    new Paragraph({
      children: [T(`${now.getFullYear()}年${now.getMonth() + 1}月${now.getDate()}日  生成  |  数据快照 2026-04-28`, { size: 18, color: C.light })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 800 },
    }),
  );

  // ==================== 一、看板概览 ====================
  children.push(Section('一、看板概览', C.accent));

  const statItems = [
    { val: '22', label: '总会话', sub: '待处理客户', color: C.accent, bg: C.accentBg },
    { val: '5', label: 'P0 紧急', sub: '今日处理', color: C.red, bg: C.redBg },
    { val: '5', label: 'P1 重要', sub: '48h内处理', color: C.orange, bg: C.orangeBg },
    { val: '12', label: 'P2/P3', sub: '本周处理', color: C.yellow, bg: C.yellowBg },
  ];

  children.push(
    new Table({
      rows: [
        new TableRow({
          children: statItems.map(s =>
            new TableCell({
              children: [
                new Paragraph({
                  children: [T(s.val, { size: 40, bold: true, color: s.color, font: FONT_MONO })],
                  alignment: AlignmentType.CENTER,
                  spacing: { after: 20 },
                }),
                new Paragraph({
                  children: [T(s.label, { size: 20, bold: true, color: C.ink })],
                  alignment: AlignmentType.CENTER,
                  spacing: { after: 8 },
                }),
                new Paragraph({
                  children: [T(s.sub, { size: 16, color: C.light })],
                  alignment: AlignmentType.CENTER,
                }),
              ],
              shading: { fill: s.bg, type: ShadingType.CLEAR },
              width: { size: 2200, type: WidthType.DXA },
              margins: { top: 240, bottom: 240 },
              borders: {
                top: { style: BorderStyle.NONE },
                bottom: { style: BorderStyle.NONE },
                left: { style: BorderStyle.NONE },
                right: { style: BorderStyle.NONE },
              },
            })
          ),
        }),
      ],
      width: { size: 100, type: WidthType.PERCENTAGE },
      layout: TableLayoutType.FIXED,
    }),
  );

  children.push(Spacer(100));

  // 分类明细表
  children.push(new Paragraph({
    children: [T('客户分类明细', { size: 24, bold: true, color: C.ink })],
    spacing: { before: 160, after: 120 },
  }));

  const catHeaderRow = new TableRow({
    tableHeader: true,
    children: [
      { w: 1700, t: '分类' },
      { w: 600, t: '人数' },
      { w: 6500, t: '客户' },
    ].map(h =>
      new TableCell({
        children: [
          new Paragraph({
            children: [T(h.t, { size: 18, bold: true, color: C.white })],
            alignment: h.w === 600 ? AlignmentType.CENTER : AlignmentType.LEFT,
          }),
        ],
        shading: { fill: C.accent, type: ShadingType.CLEAR },
        width: { size: h.w, type: WidthType.DXA },
        margins: { top: 80, bottom: 80, left: 80, right: 80 },
      })
    ),
  });

  const catData = [
    ['P0 · 今日紧急', '5', 'amer ly (伊拉克), azaan ss, zainab Babesets (伊拉克), Amal Alamhrooqi (阿曼), Ahmed Darrat', C.red],
    ['P1 · 48h内', '5', 'Krisgel Igros (菲律宾), fernande Pochette (美国/Mohammed), Aula Alsaad, Susuanna ParkerAdentwi (加纳), rehema kiseyu (坦桑尼亚)', C.orange],
    ['P2 · 本周内', '6', 'Cindy Nadal (法语区), Sifa Vano, Regina Kabanda, Adm Reda, Sayfullaeva Shahnoza, maimouna cisse (法语区)', C.yellow],
    ['P3 · 低活跃', '6', 'TheodoraAdelaide Mahe, Fathima (印度), Jemima Piema, Assiatou Barry, Lohgah Sharon, 同行推销', C.light],
  ];

  children.push(
    new Table({
      rows: [catHeaderRow, ...catData.map((r, i) =>
        new TableRow({
          children: [
            new TableCell({
              children: [new Paragraph({ children: [T(r[0], { size: 18, bold: true, color: r[3] })] })],
              margins: { top: 70, bottom: 70, left: 80, right: 80 },
              width: { size: 1700, type: WidthType.DXA },
              shading: { fill: i % 2 === 0 ? C.white : C.tableBg, type: ShadingType.CLEAR },
            }),
            new TableCell({
              children: [new Paragraph({ children: [T(r[1], { size: 20, bold: true, color: C.soft, font: FONT_MONO })], alignment: AlignmentType.CENTER })],
              width: { size: 600, type: WidthType.DXA },
              shading: { fill: i % 2 === 0 ? C.white : C.tableBg, type: ShadingType.CLEAR },
            }),
            new TableCell({
              children: [new Paragraph({ children: [T(r[2], { size: 17, color: C.soft })] })],
              width: { size: 6500, type: WidthType.DXA },
              shading: { fill: i % 2 === 0 ? C.white : C.tableBg, type: ShadingType.CLEAR },
            }),
          ],
        })
      )],
      width: { size: 100, type: WidthType.PERCENTAGE },
      layout: TableLayoutType.FIXED,
    }),
  );

  // ================================================================
  // 二、P0 深度分析
  // ================================================================
  children.push(Divider());
  children.push(Section('二、P0 今日紧急 · 深度策略推演', C.red));

  // ==================== 1. amer ly ====================
  children.push(...DeepCard('1. amer ly — 伊拉克 — S级 — 已报价待付款', [
    { type: 'section', label: '一、当前卡点诊断' },
    { type: 'text', value: '已发完整报价：$3.80/pc × 28件（7色×4码）= $106.40，DHL运费 $157 DAP到伊拉克Nasiriyah，总价 $263.40。客户Apr 28主动催过"هل أكملت؟"（弄好了吗？），说明有紧迫感。我方已发PI文件。' },
    { type: 'text', value: '核心判断：客户要的是现货，不是定制生产。28件=7色×4码各1件的组合说明：这是小批量试单/样品单，不是常规批发订单。$157运费占了总价的60%，这很可能是客户犹豫的核心原因。' },
    { type: 'text', value: '客户画像：伊拉克Nasiriyah，阿拉伯语，很可能是个体店主/小批发商。小批量试单说明他在测试市场，如果不满意运费/总价，可能找其他供应商。' },

    { type: 'section', label: '二、跟进策略博弈分析' },
    { type: 'compare', options: [
      { name: '方案A：追问"收到了吗"', actions: '发一条"هل استلمت الفاتورة؟"（收到发票了吗？）', risks: '被动、显得急、没有给客户新信息，回复率低', verdict: '❌ 不推荐', verdictColor: C.red },
      { name: '方案B：直接催付款', actions: '发付款链接，问TT还是TA', risks: '如果客户在犹豫运费，催付款会让他直接放弃', verdict: '⚠️ 风险大', verdictColor: C.orange },
      { name: '方案C：给选择权', actions: '确认现货库存，提供两种物流方案对比（DHL快但贵 vs 海运慢但便宜），让客户自己选', risks: '客户可能选更便宜的海运，你的运费收入降低', verdict: '✅ 推荐', verdictColor: C.green },
    ]},
