#!/usr/bin/env node

/**
 * 小满CRM — 客户执行方案生成器 v3
 * 输出专业排版的 Word 文档到桌面
 * 特点：中文话术 / 深度策略推演 / 多方案对比 / 风险预判
 */

import { writeFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
import {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, WidthType, BorderStyle, ShadingType, TableLayoutType,
} from 'docx';

const __dirname = dirname(fileURLToPath(import.meta.url));
const DESKTOP = 'C:/Users/Administrator/Desktop';

// ============================================================
// 调色板 — 专业商务风格
// ============================================================
const C = {
  ink:      '1E1E1E',   // 正文黑
  soft:     '5C5C5C',   // 辅助灰
  light:    '8C8C8C',   // 轻灰
  line:     'D0D0D0',   // 分隔线
  accent:   '1A3A8A',   // 深蓝主强调
  accentBg: 'EDF1FA',   // 浅蓝底
  red:      'B71C1C',   // 警示红
  redBg:    'FFF0F0',   // 红底
  orange:   'C05A00',   // 高优橙
  orangeBg: 'FFF6ED',   // 橙底
  yellow:   '7A6300',   // 关注黄
  yellowBg: 'FFFCE8',   // 黄底
  green:    '1E6E2E',   // 行动绿
  greenBg:  'EDF7EF',   // 绿底
  purple:   '5C2D91',   // 紫色
  teal:     '0D6B6B',   // 青色
  white:    'FFFFFF',
  bg:       'FAFBFD',
  tableBg:  'F5F6FA',   // 表格底色
};

// ============================================================
// 排版工具
// ============================================================
const FONT = 'Microsoft YaHei';
const FONT_MONO = 'Consolas';

function T(text, opts = {}) {
  return new TextRun({
    text,
    size: opts.size || 21,
    color: opts.color || C.ink,
    bold: opts.bold || false,
    italics: opts.italics || false,
    font: opts.font || FONT,
  });
}

function P(runs, opts = {}) {
  return new Paragraph({
    children: Array.isArray(runs) ? runs : [runs],
    spacing: {
      before: opts.before || 0,
      after: opts.after ?? 80,
      line: opts.line || 360,
    },
    indent: opts.indent,
    alignment: opts.alignment || AlignmentType.LEFT,
    border: opts.border,
    shading: opts.shading,
  });
}

function Spacer(h = 8) {
  return new Paragraph({ spacing: { before: h, after: h } });
}

function Divider() {
  return new Paragraph({
    children: [],
    spacing: { before: 140, after: 140 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 1, color: C.line } },
  });
}

function Section(title, color) {
  return new Paragraph({
    children: [
      T(title, { size: 32, bold: true, color: color || C.accent }),
    ],
    spacing: { before: 400, after: 200 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: color || C.accent } },
  });
}

// 深度分析卡片 - 用于P0客户
function DeepCard(title, blocks, { color = C.accent, bgColor = C.accentBg } = {}) {
  const items = [];

  // 标题
  items.push(new Paragraph({
    children: [T(title, { size: 26, bold: true, color })],
    spacing: { before: 240, after: 100 },
    shading: { fill: bgColor, type: ShadingType.CLEAR },
    indent: { left: 200, right: 200 },
    border: {
      left: { style: BorderStyle.SINGLE, size: 10, color },
      bottom: { style: BorderStyle.SINGLE, size: 1, color: C.line },
    },
  }));

  for (const block of blocks) {
    if (block.type === 'section') {
      items.push(new Paragraph({
        children: [T('▌' + block.label, { size: 22, bold: true, color: C.ink })],
        spacing: { before: 120, after: 80 },
        indent: { left: 400 },
      }));
    } else if (block.type === 'text') {
      items.push(new Paragraph({
        children: [T(block.value, { size: 20, color: C.ink })],
        spacing: { after: 50 },
        indent: { left: 600 },
      }));
    } else if (block.type === 'compare') {
      // 方案对比表
      const rows = [
        new TableRow({
          tableHeader: true,
          children: ['方案', '做法', '风险', '判断'].map((h, i) =>
            new TableCell({
              children: [new Paragraph({
                children: [T(h, { size: 18, bold: true, color: C.white })],
                alignment: AlignmentType.CENTER,
              })],
              shading: { fill: color, type: ShadingType.CLEAR },
              width: { size: i === 0 ? 1200 : i === 3 ? 1000 : 2000, type: WidthType.DXA },
              margins: { top: 60, bottom: 60, left: 60, right: 60 },
            })
          ),
        }),
        ...block.options.map((opt, i) => {
          const bg = i % 2 === 0 ? C.white : C.tableBg;
          return new TableRow({
            children: [
              new TableCell({
                children: [new Paragraph({ children: [T(opt.name, { size: 18, bold: true, color: C.ink })], alignment: AlignmentType.CENTER })],
                shading: { fill: bg, type: ShadingType.CLEAR },
                margins: { top: 60, bottom: 60, left: 60, right: 60 },
              }),
              new TableCell({
                children: [new Paragraph({ children: [T(opt.actions, { size: 17, color: C.soft })] })],
                shading: { fill: bg, type: ShadingType.CLEAR },
                margins: { top: 60, bottom: 60, left: 60, right: 60 },
              }),
              new TableCell({
                children: [new Paragraph({ children: [T(opt.risks, { size: 17, color: C.red })] })],
                shading: { fill: bg, type: ShadingType.CLEAR },
                margins: { top: 60, bottom: 60, left: 60, right: 60 },
              }),
              new TableCell({
                children: [new Paragraph({ children: [T(opt.verdict, { size: 17, bold: true, color: opt.verdictColor || C.green })] })],
                shading: { fill: bg, type: ShadingType.CLEAR },
                margins: { top: 60, bottom: 60, left: 60, right: 60 },
              }),
            ],
          });
        }),
      ];

      items.push(
        new Table({
          rows,
          width: { size: 100, type: WidthType.PERCENTAGE },
          layout: TableLayoutType.FIXED,
        }),
      );
    } else if (block.type === 'strategy') {
      items.push(new Paragraph({
        children: [T('► 推荐策略：' + block.value, { size: 20, bold: true, color: C.green })],
        spacing: { before: 80, after: 60 },
        indent: { left: 600 },
      }));
    } else if (block.type === 'reply') {
      items.push(new Paragraph({
        children: [
          T('回复话术（中文）：', { size: 19, bold: true, color: C.green }),
        ],
        spacing: { before: 80, after: 40 },
        indent: { left: 400 },
      }));
      items.push(new Paragraph({
        children: [T(block.text, { size: 19, color: C.ink })],
        spacing: { after: 60 },
        indent: { left: 600, right: 200 },
        shading: { fill: C.greenBg, type: ShadingType.CLEAR },
        border: {
          left: { style: BorderStyle.SINGLE, size: 5, color: C.green },
          top: { style: BorderStyle.SINGLE, size: 1, color: C.line },
          bottom: { style: BorderStyle.SINGLE, size: 1, color: C.line },
          right: { style: BorderStyle.SINGLE, size: 1, color: C.line },
        },
      }));
    } else if (block.type === 'logic') {
      items.push(new Paragraph({
        children: [T(block.label, { size: 19, bold: true, color: C.purple })],
        spacing: { before: 60, after: 30 },
        indent: { left: 400 },
      }));
      items.push(new Paragraph({
        children: [T(block.text, { size: 18, color: C.soft })],
        spacing: { after: 40 },
        indent: { left: 600 },
      }));
    } else if (block.type === 'pricing') {
      items.push(new Paragraph({
        children: [T('定价推算：' + block.text, { size: 19, color: C.orange, italics: true })],
        spacing: { before: 40, after: 40 },
        indent: { left: 600 },
        shading: { fill: C.orangeBg, type: ShadingType.CLEAR },
      }));
    } else if (block.type === 'trigger') {
      items.push(new Paragraph({
        children: [T('⏎ 后续动作：' + block.text, { size: 19, bold: true, color: C.red })],
        spacing: { before: 80, after: 40 },
        indent: { left: 400 },
        border: { left: { style: BorderStyle.SINGLE, size: 4, color: C.red } },
      }));
    }
  }

  return items;
}

// 标准卡片 - 用于P1客户
function StdCard(title, contents, { color = C.accent, bgColor = C.accentBg } = {}) {
  const items = [];
  items.push(new Paragraph({
    children: [T(title, { size: 24, bold: true, color })],
    spacing: { before: 200, after: 80 },
    shading: { fill: bgColor, type: ShadingType.CLEAR },
    indent: { left: 200 },
    border: { left: { style: BorderStyle.SINGLE, size: 6, color } },
  }));

  for (const item of contents) {
    if (item.type === 'diag') {
      items.push(new Paragraph({
        children: [T('现状：' + item.text, { size: 19, color: C.ink })],
        spacing: { after: 40 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'strat') {
      items.push(new Paragraph({
        children: [T('策略：' + item.text, { size: 19, bold: true, color: C.ink })],
        spacing: { before: 40, after: 40 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'reply') {
      items.push(new Paragraph({
        children: [T('话术：', { size: 18, bold: true, color: C.green }), T(item.text, { size: 18, color: C.ink })],
        spacing: { after: 40 },
        indent: { left: 560 },
        shading: { fill: C.greenBg, type: ShadingType.CLEAR },
        border: { left: { style: BorderStyle.SINGLE, size: 3, color: C.green } },
      }));
    } else if (item.type === 'trigger') {
      items.push(new Paragraph({
        children: [T('触发：' + item.text, { size: 18, color: C.orange })],
        spacing: { after: 30 },
        indent: { left: 500 },
      }));
    } else if (item.type === 'warn') {
      items.push(new Paragraph({
        children: [T('注意：' + item.text, { size: 18, color: C.red, bold: true })],
        spacing: { before: 20, after: 20 },
        indent: { left: 500 },
      }));
    }
  }
  return items;
}


