file.content:
#!/usr/bin/env node

/**
 * 小满CRM — 客户执行方案生成器 v3
 * 输出专业排版的 Word 文档到桌面

input.command:
cd "d:/ClaudeWorkspace/08_客户跟进/Okki/scripts" && node -e "
const fs = require('fs');
let s = fs.readFileSync('generate-action-plan.mjs','utf8');

// 1. Fix pricing formula: 0.6 -> 0.65
s = s.replace(/÷ 0\.6 ÷/g, '÷ 0.65 ÷');

// 2. Fix the example calculation
s = s.replace(/\$3\.72 → 报价\$3\.80/g, '\$3.44 → 报价\$3.45');
s = s.replace(/3\.72×28−3\.72×28≈2\.24/g, '3.45×28-3.44×28≈0.28');
s = s.replace(/利润极薄/g, '利润来自走量');

// 3. Fix the formula in appendix
s = s.replace(/15\.2 ÷ 0\.6 ÷ 6\.8 = \$3\.72 → 报价\$3\.80/g, '15.2 ÷ 0.65 ÷ 6.8 = \$3.44 → 报价\$3.45');

// 4. Fix the standalone formula line
s = s.replace(/成本\(RMB\) ÷ 0\.6 ÷ 6\.8/g, '成本(RMB) ÷ 0.65 ÷ 6.8');

fs.writeFileSync('generate-action-plan.mjs', s);
console.log('Pricing fixes applied');
"

